import { ReactNode } from "react";
import { Link, useLocation } from "wouter";
import { useAuth } from "@/contexts/AuthContext";
import { useTenant } from "@/contexts/TenantContext";
import { useLogout } from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import {
  LayoutDashboard, BookOpen, Award, MessageSquare, Clock, Library,
  Users, GraduationCap, CheckSquare, Calendar, LogOut, ChevronRight,
  ClipboardCheck
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { NotificationBell } from "@/components/NotificationBell";

interface NavItem {
  label: string;
  href: string;
  icon: ReactNode;
}

const studentNav: NavItem[] = [
  { label: "Dashboard", href: "/student", icon: <LayoutDashboard size={17} /> },
  { label: "Academics", href: "/student/academics", icon: <BookOpen size={17} /> },
  { label: "Timetable", href: "/student/timetable", icon: <Clock size={17} /> },
  { label: "StudyVault", href: "/student/notes", icon: <Library size={17} /> },
  { label: "Scholarships", href: "/student/scholarship", icon: <Award size={17} /> },
  { label: "Grievance", href: "/student/grievance", icon: <MessageSquare size={17} /> },
];

const parentNav: NavItem[] = [
  { label: "Dashboard", href: "/parent", icon: <LayoutDashboard size={17} /> },
  { label: "Proctor Chat", href: "/parent/chat", icon: <MessageSquare size={17} /> },
];

const facultyNav: NavItem[] = [
  { label: "Dashboard", href: "/faculty", icon: <LayoutDashboard size={17} /> },
  { label: "Student Roster", href: "/faculty/students", icon: <Users size={17} /> },
  { label: "Academics", href: "/faculty/academics", icon: <GraduationCap size={17} /> },
  { label: "Attendance", href: "/faculty/attendance", icon: <ClipboardCheck size={17} /> },
  { label: "StudyVault", href: "/faculty/notes", icon: <Library size={17} /> },
  { label: "Timetable", href: "/faculty/timetable", icon: <Calendar size={17} /> },
];

interface PortalLayoutProps {
  children: ReactNode;
  theme: "student" | "parent" | "faculty";
}

const sidebarConfig = {
  student: {
    bg: "bg-[#0c2340]",
    accent: "bg-blue-500/20 text-blue-200 border-l-2 border-blue-400",
    hover: "hover:bg-white/5 hover:text-white",
    logoRing: "ring-blue-400/30",
    dot: "bg-blue-400",
  },
  parent: {
    bg: "bg-emerald-900",
    accent: "bg-emerald-400/20 text-emerald-100 border-l-2 border-emerald-400",
    hover: "hover:bg-white/5 hover:text-white",
    logoRing: "ring-emerald-400/30",
    dot: "bg-emerald-400",
  },
  faculty: {
    bg: "bg-rose-900",
    accent: "bg-rose-400/20 text-rose-100 border-l-2 border-rose-400",
    hover: "hover:bg-white/5 hover:text-white",
    logoRing: "ring-rose-400/30",
    dot: "bg-rose-400",
  },
};

export function PortalLayout({ children, theme }: PortalLayoutProps) {
  const { user, setUser } = useAuth();
  const tenant = useTenant();
  const [location] = useLocation();
  const queryClient = useQueryClient();
  const { mutate: logout } = useLogout();

  const navItems = theme === "student" ? studentNav : theme === "parent" ? parentNav : facultyNav;
  const themeClass = theme === "parent" ? "theme-parent" : theme === "faculty" ? "theme-faculty" : "";
  const cfg = sidebarConfig[theme];

  function handleLogout() {
    logout(undefined, {
      onSuccess: () => {
        queryClient.clear();
        setUser(null);
        window.location.href = "/login";
      },
    });
  }

  const initials = user?.name?.split(" ").map((n) => n[0]).join("").slice(0, 2).toUpperCase() ?? "?";

  return (
    <div className={`min-h-screen w-full flex ${themeClass}`}>
      {/* Sidebar */}
      <aside className={`w-64 min-h-screen flex flex-col fixed left-0 top-0 bottom-0 z-30 ${cfg.bg}`}>
        {/* Brand */}
        <div className="px-5 py-4 border-b border-white/10">
          <div className="flex items-center gap-3">
            <div className={`flex-shrink-0 w-10 h-10 rounded-xl overflow-hidden ring-2 ${cfg.logoRing} bg-white flex items-center justify-center`}>
              <img src="/rnsit-logo.png" alt="RNSIT" className="w-10 h-10 object-cover" />
            </div>
            <div className="flex-1 min-w-0">
              <div className="font-bold text-white text-sm leading-tight">RNSIT</div>
              <div className="text-white/50 text-[10px] tracking-wide uppercase">Guardian Network</div>
            </div>
            {theme === "parent" && <NotificationBell />}
          </div>
        </div>

        {/* Portal label */}
        <div className="px-5 py-2.5">
          <div className={`inline-flex items-center gap-1.5 text-[10px] font-semibold uppercase tracking-widest px-2.5 py-1 rounded-full bg-white/10 text-white/60`}>
            <div className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`} />
            {theme} Portal
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 py-2 px-3 space-y-0.5 overflow-y-auto">
          {navItems.map((item) => {
            const rootHref = `/${theme}`;
            const isActive =
              location === item.href ||
              (item.href !== rootHref && location.startsWith(item.href));
            return (
              <Link
                key={item.href}
                href={item.href}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-150 ${
                  isActive
                    ? cfg.accent
                    : `text-white/60 ${cfg.hover}`
                }`}
              >
                <span className={isActive ? "opacity-100" : "opacity-60"}>{item.icon}</span>
                {item.label}
                {isActive && <ChevronRight size={13} className="ml-auto opacity-40" />}
              </Link>
            );
          })}
        </nav>

        {/* User section */}
        <div className="p-4 border-t border-white/10">
          <div className="flex items-center gap-3 mb-3">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold bg-white/15 text-white ring-1 ring-white/20`}>
              {initials}
            </div>
            <div className="flex-1 min-w-0">
              <div className="text-white text-xs font-semibold truncate">{user?.name}</div>
              <div className="text-white/40 text-[10px] capitalize">{user?.role} · RNSIT</div>
            </div>
          </div>
          <button
            onClick={handleLogout}
            className="w-full flex items-center gap-2 px-3 py-2 rounded-lg text-white/50 hover:text-white hover:bg-white/10 text-xs font-medium transition-all"
          >
            <LogOut size={13} />
            Sign Out
          </button>
        </div>
      </aside>

      {/* Main content */}
      <main className="flex-1 ml-64 min-h-screen bg-gray-50/80">
        {children}
      </main>
    </div>
  );
}

@import "tailwindcss";
@import "tw-animate-css";
@plugin "@tailwindcss/typography";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: hsl(var(--background));
  --color-foreground: hsl(var(--foreground));
  --color-border: hsl(var(--border));
  --color-input: hsl(var(--input));
  --color-ring: hsl(var(--ring));

