import { useGetStudentDashboard, getGetStudentDashboardQueryKey } from "@workspace/api-client-react";
import { PortalLayout } from "@/components/PortalLayout";
import { useAuth } from "@/contexts/AuthContext";
import { RequireAuth } from "@/contexts/AuthContext";
import { Link } from "wouter";
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell,
  RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
} from "recharts";
import { TrendingUp, TrendingDown, BookOpen, Award, MessageSquare, Clock, Library, AlertTriangle, CheckCircle, Quote, Zap } from "lucide-react";

function QuickCard({ href, icon, label, color }: { href: string; icon: React.ReactNode; label: string; color: string }) {
  return (
    <Link href={href} className={`flex flex-col items-center justify-center p-4 rounded-xl ${color} text-white hover:opacity-90 transition-all duration-150 hover:scale-105 cursor-pointer shadow-sm`}>
      <div className="mb-2">{icon}</div>
      <span className="text-xs font-semibold text-center">{label}</span>
    </Link>
  );
}

const CUSTOM_TOOLTIP = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white border border-gray-100 rounded-lg shadow-lg px-3 py-2 text-xs">
        <p className="font-semibold text-gray-700 mb-1">{label}</p>
        <p className="text-gray-500">{payload[0].value.toFixed(1)}%</p>
      </div>
    );
  }
  return null;
};

function StudentDashboardContent() {
  const { user } = useAuth();
  const { data, isLoading } = useGetStudentDashboard({
    query: { queryKey: getGetStudentDashboardQueryKey() },
  });

  if (isLoading) {
    return (
      <div className="p-8 max-w-7xl mx-auto">
        <div className="animate-pulse space-y-5">
          <div className="h-32 bg-gray-200 rounded-2xl" />
          <div className="grid grid-cols-3 gap-4">
            {[1,2,3].map(i => <div key={i} className="h-28 bg-gray-200 rounded-2xl" />)}
          </div>
          <div className="grid grid-cols-3 gap-4">
            <div className="col-span-2 h-64 bg-gray-200 rounded-2xl" />
            <div className="h-64 bg-gray-200 rounded-2xl" />
          </div>
        </div>
      </div>
    );
  }

  const academics = data?.academics;
  const subjects = data?.subjectRecords ?? [];
  const timetable = data?.upcomingTimetable ?? [];
  const grievances = data?.recentGrievances ?? [];
  const quote = data?.dailyQuote ?? "The only way to do great work is to love what you do.";

  const sgpa = academics ? Number(academics.sgpa) : 0;
  const cgpa = academics ? Number(academics.cgpa) : 0;
  const overallAtt = academics ? Number(academics.overallAttendance) : 0;

  const attChartData = subjects.slice(0, 6).map((s) => ({
    name: s.subject.split(" ").slice(0, 2).join(" "),
    value: Number(s.attendance),
  }));

  const marksChartData = subjects.filter(s => s.cie1 != null).map((s) => ({
    subject: s.subject.split(" ")[0],
    CIE1: Number(s.cie1 ?? 0),
    CIE2: Number(s.cie2 ?? 0),
  }));

  return (
    <div className="min-h-screen">
      {/* Hero header */}
      <div className="page-header-student px-8 pt-8 pb-16">
        <div className="max-w-7xl mx-auto">
          <div className="flex items-start justify-between">
            <div>
              <p className="text-blue-300 text-sm font-medium mb-1">Welcome back</p>
              <h1 className="text-3xl font-bold text-white mb-3">
                {user?.name?.split(" ")[0]} 👋
              </h1>
              <div className="flex items-center gap-2 text-blue-200/70 text-sm">
                <Quote size={12} className="flex-shrink-0" />
                <em className="italic">{quote}</em>
              </div>
            </div>
            <div className="text-right hidden md:block">
              <img src="/rnsit-logo.png" alt="RNSIT" className="w-14 h-14 rounded-xl object-cover opacity-80" />
            </div>
          </div>

          {/* Stat cards in header */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8">
            <div className="bg-white/10 backdrop-blur rounded-2xl p-5 border border-white/15">
              <p className="text-blue-200 text-xs font-medium mb-1">SGPA (Current Sem)</p>
              <p className="text-3xl font-bold text-white">{sgpa.toFixed(2)}</p>
              <div className="flex items-center gap-1 mt-1 text-xs text-blue-300">
                {sgpa >= 7 ? <TrendingUp size={11} /> : <TrendingDown size={11} className="text-red-300" />}
                <span>{sgpa >= 8 ? "Excellent" : sgpa >= 6 ? "Good" : "Needs Improvement"}</span>
              </div>
            </div>
            <div className="bg-white/10 backdrop-blur rounded-2xl p-5 border border-white/15">
              <p className="text-blue-200 text-xs font-medium mb-1">CGPA (Cumulative)</p>
              <p className="text-3xl font-bold text-white">{cgpa.toFixed(2)}</p>
              <div className="flex items-center gap-1 mt-1 text-xs text-blue-300">
                <TrendingUp size={11} /> <span>Across all semesters</span>
              </div>
            </div>
            <div className={`rounded-2xl p-5 border ${overallAtt < 85 ? "bg-red-500/20 border-red-400/30" : "bg-emerald-500/20 border-emerald-400/30"}`}>
              <p className={`text-xs font-medium mb-1 ${overallAtt < 85 ? "text-red-200" : "text-emerald-200"}`}>Overall Attendance</p>
              <p className={`text-3xl font-bold ${overallAtt < 85 ? "text-red-100" : "text-white"}`}>{overallAtt.toFixed(1)}%</p>
              <div className={`flex items-center gap-1 mt-1 text-xs ${overallAtt < 85 ? "text-red-300" : "text-emerald-300"}`}>
                {overallAtt < 85 ? <AlertTriangle size={11} /> : <CheckCircle size={11} />}
                <span>{overallAtt < 85 ? "Below 85% — Action needed" : "Above 85% — Keep it up!"}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="max-w-7xl mx-auto px-8 -mt-8 pb-10">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Left — Charts */}
          <div className="lg:col-span-2 space-y-6">
            {/* Attendance Bar Chart */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <h2 className="font-bold text-gray-900 mb-1">Subject-wise Attendance</h2>
              <p className="text-xs text-gray-400 mb-5">Class attendance percentage per subject</p>
              {subjects.length > 0 ? (
                <>
                  <ResponsiveContainer width="100%" height={180}>
                    <BarChart data={attChartData} barSize={32} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
                      <XAxis dataKey="name" tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                      <YAxis domain={[0, 100]} tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                      <Tooltip content={<CUSTOM_TOOLTIP />} cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                      <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                        {attChartData.map((entry, i) => (
                          <Cell key={i} fill={entry.value < 75 ? "#ef4444" : entry.value < 85 ? "#f59e0b" : "#10b981"} />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                  <div className="flex items-center gap-4 mt-3 text-[10px] text-gray-400">
                    <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-emerald-500 inline-block" />≥85% Good</span>
                    <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-amber-400 inline-block" />75–85% Warning</span>
                    <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-red-500 inline-block" />&lt;75% Critical</span>
                  </div>
                </>
              ) : (
                <p className="text-gray-300 text-sm text-center py-8">No subject records yet.</p>
              )}
            </div>

            {/* CIE Marks Chart */}
            {marksChartData.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                <h2 className="font-bold text-gray-900 mb-1">CIE Marks Comparison</h2>
                <p className="text-xs text-gray-400 mb-5">CIE 1 vs CIE 2 scores (out of 20)</p>
                <ResponsiveContainer width="100%" height={160}>
                  <BarChart data={marksChartData} barSize={14} barGap={3} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
                    <XAxis dataKey="subject" tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                    <YAxis domain={[0, 20]} tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                    <Tooltip cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                    <Bar dataKey="CIE1" fill="#3b82f6" radius={[4, 4, 0, 0]} name="CIE 1" />
                    <Bar dataKey="CIE2" fill="#0c2340" radius={[4, 4, 0, 0]} name="CIE 2" />
                  </BarChart>
                </ResponsiveContainer>
                <div className="flex items-center gap-4 mt-3 text-[10px] text-gray-400">
                  <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-blue-400 inline-block" />CIE 1</span>
                  <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-[#0c2340] inline-block" />CIE 2</span>
                </div>
              </div>
            )}
          </div>

          {/* Right — Quick actions + upcoming */}
          <div className="space-y-5">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5">
              <h3 className="font-bold text-gray-900 mb-4 text-sm flex items-center gap-2">
                <Zap size={14} className="text-amber-500" /> Quick Access
              </h3>
              <div className="grid grid-cols-2 gap-2">
                <QuickCard href="/student/academics" icon={<BookOpen size={18} />} label="Marks" color="bg-[#0c2340]" />
                <QuickCard href="/student/timetable" icon={<Clock size={18} />} label="Timetable" color="bg-indigo-600" />
                <QuickCard href="/student/notes" icon={<Library size={18} />} label="StudyVault" color="bg-violet-600" />
                <QuickCard href="/student/scholarship" icon={<Award size={18} />} label="Scholarships" color="bg-amber-600" />
                <QuickCard href="/student/grievance" icon={<MessageSquare size={18} />} label="Grievance" color="bg-slate-600" />
              </div>
            </div>

            {/* Upcoming classes */}
            {timetable.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5">
                <h3 className="font-bold text-gray-900 mb-3 text-sm flex items-center gap-2">
                  <Clock size={14} className="text-blue-500" /> Upcoming Classes
                </h3>
                <div className="space-y-1.5">
                  {timetable.slice(0, 4).map((t) => (
                    <div key={t.id} className="flex items-center gap-3 p-2.5 rounded-lg bg-gray-50 hover:bg-gray-100 transition-colors">
                      <div className="w-10 text-[10px] font-bold text-blue-600 flex-shrink-0">{t.startTime}</div>
                      <div className="flex-1 min-w-0">
                        <div className="text-xs font-semibold text-gray-800 truncate">{t.subject}</div>
                        <div className="text-[10px] text-gray-400">{t.dayOfWeek} · {t.room ?? "—"}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Grievance status */}
            {grievances.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5">
                <h3 className="font-bold text-gray-900 mb-3 text-sm flex items-center gap-2">
                  <MessageSquare size={14} className="text-gray-400" /> Grievances
                </h3>
                {grievances.slice(0, 2).map((g) => (
                  <div key={g.id} className="flex items-center gap-2.5 py-2 border-b border-gray-50 last:border-0">
                    <div className={`w-2 h-2 rounded-full flex-shrink-0 ${g.status === "resolved" ? "bg-emerald-400" : g.status === "in_progress" ? "bg-amber-400" : "bg-gray-300"}`} />
                    <div className="text-xs text-gray-600 truncate flex-1">{g.isAnonymous ? "Anonymous" : g.title}</div>
                    <div className="text-[10px] text-gray-400 capitalize px-2 py-0.5 bg-gray-100 rounded-full">{g.status?.replace("_", " ")}</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default function StudentDashboard() {
  return (
    <RequireAuth allowedRoles={["student"]}>
      <PortalLayout theme="student">
        <StudentDashboardContent />
      </PortalLayout>
    </RequireAuth>
  );
