import { useAuth, RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { useGetAcademics, useGetSubjectRecords, getGetAcademicsQueryKey, getGetSubjectRecordsQueryKey } from "@workspace/api-client-react";
