import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell,
  RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
} from "recharts";

function AcademicsContent() {
  const { user } = useAuth();
  const { data: academics, isLoading: aLoading } = useGetAcademics(user?.id ?? 0, {
    query: { enabled: !!user?.id, queryKey: getGetAcademicsQueryKey(user?.id ?? 0) },
  });
  const { data: subjects, isLoading: sLoading } = useGetSubjectRecords(user?.id ?? 0, {
    query: { enabled: !!user?.id, queryKey: getGetSubjectRecordsQueryKey(user?.id ?? 0) },
  });

  if (aLoading || sLoading) {
    return (
      <div className="p-8 max-w-7xl mx-auto">
        <div className="animate-pulse space-y-4">
          <div className="h-32 bg-gray-200 rounded-2xl" />
          <div className="h-64 bg-gray-200 rounded-2xl" />
        </div>
      </div>
    );
  }

  const subjectList = subjects ?? [];

  const attChartData = subjectList.map((s) => ({
    name: s.subject.split(" ")[0],
    value: Number(s.attendance),
  }));

  const marksRadarData = subjectList.map((s) => ({
    subject: s.subject.split(" ")[0],
    CIE1: Number(s.cie1 ?? 0),
    CIE2: Number(s.cie2 ?? 0),
    AAT: Number(s.aat1 ?? 0),
  }));

  const marksBarData = subjectList.map((s) => ({
    name: s.subject.split(" ")[0],
    CIE1: Number(s.cie1 ?? 0),
    CIE2: Number(s.cie2 ?? 0),
    Lab: Number(s.lab ?? 0),
  }));

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-student px-8 pt-8 pb-14">
        <div className="max-w-7xl mx-auto">
          <p className="text-blue-300 text-xs font-semibold uppercase tracking-wider mb-2">Academic Records</p>
          <h1 className="text-2xl font-bold text-white mb-6">Your Performance</h1>
          <div className="grid grid-cols-3 gap-4">
            <div className="bg-white/10 backdrop-blur rounded-xl p-5 border border-white/15">
              <p className="text-blue-200 text-xs mb-1">SGPA</p>
