            </div>
            <div className={`rounded-xl p-5 border ${academics && Number(academics.overallAttendance) < 85 ? "bg-red-500/20 border-red-400/30" : "bg-emerald-500/20 border-emerald-400/30"}`}>
              <p className={`text-xs mb-1 ${academics && Number(academics.overallAttendance) < 85 ? "text-red-200" : "text-emerald-200"}`}>Overall Attendance</p>
