          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 -mt-6 pb-10 space-y-6">
        {/* Charts row */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Attendance chart */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <h2 className="font-bold text-gray-900 mb-1">Subject Attendance</h2>
            <p className="text-xs text-gray-400 mb-4">% attendance per subject</p>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={attChartData} barSize={28} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
                <XAxis dataKey="name" tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                <YAxis domain={[0, 100]} tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                <Tooltip formatter={(v: any) => [`${Number(v).toFixed(1)}%`, "Attendance"]} cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                  {attChartData.map((entry, i) => (
                    <Cell key={i} fill={entry.value < 75 ? "#ef4444" : entry.value < 85 ? "#f59e0b" : "#10b981"} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Marks chart */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <h2 className="font-bold text-gray-900 mb-1">CIE & Lab Scores</h2>
            <p className="text-xs text-gray-400 mb-4">CIE 1, CIE 2, Lab marks per subject</p>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={marksBarData} barSize={10} barGap={2} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
                <XAxis dataKey="name" tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fontSize: 10, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                <Tooltip cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                <Bar dataKey="CIE1" fill="#3b82f6" radius={[4, 4, 0, 0]} name="CIE 1" />
                <Bar dataKey="CIE2" fill="#0c2340" radius={[4, 4, 0, 0]} name="CIE 2" />
                <Bar dataKey="Lab" fill="#10b981" radius={[4, 4, 0, 0]} name="Lab" />
              </BarChart>
            </ResponsiveContainer>
            <div className="flex items-center gap-4 mt-2 text-[10px] text-gray-400">
              <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-blue-400 inline-block" />CIE 1</span>
              <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-[#0c2340] inline-block" />CIE 2</span>
              <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-emerald-500 inline-block" />Lab</span>
            </div>
          </div>
        </div>

        {/* Marks table */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="px-6 py-5 border-b border-gray-50 flex items-center justify-between">
            <div>
              <h2 className="font-bold text-gray-900">VTU Marks Sheet</h2>
              <p className="text-xs text-gray-400 mt-0.5">CIE 1, CIE 2, AAT 1, AAT 2, Lab & SEE</p>
            </div>
            <TrendingUp size={16} className="text-gray-300" />
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="bg-gray-50/80 text-left">
                  <th className="px-5 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider">Subject</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">Attendance</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">CIE 1</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">CIE 2</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">AAT 1</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">AAT 2</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">Lab</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">SEE</th>
                  <th className="px-4 py-3 text-[11px] font-semibold text-gray-400 uppercase tracking-wider text-center">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {subjectList.length === 0 ? (
                  <tr>
                    <td colSpan={9} className="px-5 py-12 text-center text-gray-300 text-sm">No records available yet.</td>
                  </tr>
                ) : subjectList.map((s) => {
                  const att = Number(s.attendance);
                  const attLow = att < 85;
                  return (
                    <tr key={s.id} className="hover:bg-blue-50/30 transition-colors">
                      <td className="px-5 py-3.5 font-semibold text-gray-900 text-sm">{s.subject}</td>
                      <td className="px-4 py-3.5 text-center">
                        <span className={`inline-flex items-center gap-1 text-xs font-bold px-2.5 py-1 rounded-full ${att < 75 ? "bg-red-100 text-red-700" : att < 85 ? "bg-amber-100 text-amber-700" : "bg-emerald-100 text-emerald-700"}`}>
                          {attLow ? <AlertTriangle size={10} /> : <CheckCircle size={10} />}
                          {att.toFixed(1)}%
                        </span>
                      </td>
                      {[s.cie1, s.cie2, s.aat1, s.aat2, s.lab, s.see].map((val, i) => (
                        <td key={i} className="px-4 py-3.5 text-center text-sm font-medium text-gray-700">
                          {val != null ? Number(val).toFixed(0) : <span className="text-gray-200">—</span>}
                        </td>
                      ))}
                      <td className="px-4 py-3.5 text-center">
                        {att < 75 ? (
                          <span className="text-[11px] bg-red-100 text-red-700 px-2.5 py-1 rounded-full font-semibold">Critical</span>
                        ) : att < 85 ? (
                          <span className="text-[11px] bg-amber-100 text-amber-700 px-2.5 py-1 rounded-full font-semibold">Warning</span>
                        ) : (
                          <span className="text-[11px] bg-emerald-100 text-emerald-700 px-2.5 py-1 rounded-full font-semibold">Good</span>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

