import { useState } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { useListResources, useCreateResource, getListResourcesQueryKey } from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Upload, BookOpen, Video, FileText, ChevronRight, CheckCircle, Clock, XCircle, Search, Library, Sparkles } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const streams = ["Computer Science", "Electronics", "Mechanical", "Civil", "Information Science"];
const typeIcon: Record<string, React.ReactNode> = {
  notes: <FileText size={15} />,
  video: <Video size={15} />,
  assignment: <BookOpen size={15} />,
};
const typeColor: Record<string, string> = {
  notes: "bg-blue-50 text-blue-600",
  video: "bg-red-50 text-red-600",
  assignment: "bg-amber-50 text-amber-600",
};
const statusBadge: Record<string, string> = {
  approved: "bg-emerald-50 text-emerald-700",
  pending: "bg-amber-50 text-amber-700",
  rejected: "bg-red-50 text-red-700",
};
const statusIcon: Record<string, React.ReactNode> = {
  approved: <CheckCircle size={10} />,
  pending: <Clock size={10} />,
  rejected: <XCircle size={10} />,
};

function NotesContent() {
  const [stream, setStream] = useState("");
  const [semester, setSemester] = useState<number | "">("");
  const [searchQ, setSearchQ] = useState("");
  const [showUpload, setShowUpload] = useState(false);
  const [uploadForm, setUploadForm] = useState({
    title: "", stream: "", semester: 1, subject: "", chapter: "",
    type: "notes" as "notes" | "video" | "assignment", url: "", description: "",
  });
  const queryClient = useQueryClient();
  const { toast } = useToast();

  const params = { stream: stream || undefined, semester: semester ? Number(semester) : undefined, status: "approved" as const };
  const { data: resources, isLoading } = useListResources(params, {
    query: { queryKey: getListResourcesQueryKey(params) },
  });
  const { mutate: upload, isPending } = useCreateResource();

  function handleUpload(e: React.FormEvent) {
    e.preventDefault();
    upload({ data: uploadForm }, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getListResourcesQueryKey({}) });
        setShowUpload(false);
        setUploadForm({ title: "", stream: "", semester: 1, subject: "", chapter: "", type: "notes", url: "", description: "" });
        toast({ title: "Resource submitted", description: "Your resource is pending faculty review." });
      },
    });
  }

  const filtered = (resources ?? []).filter((r) =>
    !searchQ || r.title.toLowerCase().includes(searchQ.toLowerCase()) || r.subject.toLowerCase().includes(searchQ.toLowerCase())
  );

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-student px-8 pt-8 pb-14">
        <div className="max-w-7xl mx-auto flex items-start justify-between">
          <div>
            <p className="text-blue-300 text-xs font-semibold uppercase tracking-wider mb-2">Knowledge Base</p>
            <h1 className="text-2xl font-bold text-white flex items-center gap-2">
              <Library size={22} /> StudyVault
            </h1>
            <p className="text-blue-200/70 text-sm mt-1">Browse notes, videos & assignments by stream</p>
          </div>
          <Button
            onClick={() => setShowUpload(!showUpload)}
            className={showUpload ? "bg-white text-[#0c2340] hover:bg-white/90" : "bg-white/10 hover:bg-white/20 text-white border border-white/20"}
            variant="ghost"
          >
            <Upload size={14} className="mr-2" /> Contribute Resource
          </Button>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 -mt-6 pb-10 space-y-5">
        {/* Upload form */}
        {showUpload && (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <div className="flex items-center gap-2 mb-5">
              <div className="w-8 h-8 rounded-lg bg-violet-100 flex items-center justify-center">
                <Upload size={15} className="text-violet-600" />
              </div>
              <div>
                <h2 className="font-bold text-gray-900 text-sm">Upload a Resource</h2>
                <p className="text-xs text-gray-400">Student uploads go to faculty for review</p>
              </div>
            </div>
            <form onSubmit={handleUpload} className="grid grid-cols-2 gap-4">
              <div>
                <Label className="text-xs text-gray-600">Title *</Label>
                <Input value={uploadForm.title} onChange={(e) => setUploadForm({ ...uploadForm, title: e.target.value })} className="mt-1" required />
              </div>
              <div>
                <Label className="text-xs text-gray-600">Stream *</Label>
                <select value={uploadForm.stream} onChange={(e) => setUploadForm({ ...uploadForm, stream: e.target.value })} className="w-full mt-1 border border-gray-200 rounded-lg px-3 py-2 text-sm bg-white" required>
                  <option value="">Select stream</option>
                  {streams.map((s) => <option key={s}>{s}</option>)}
                </select>
              </div>
              <div>
                <Label className="text-xs text-gray-600">Semester *</Label>
                <Input type="number" min={1} max={8} value={uploadForm.semester} onChange={(e) => setUploadForm({ ...uploadForm, semester: Number(e.target.value) })} className="mt-1" required />
              </div>
              <div>
                <Label className="text-xs text-gray-600">Subject *</Label>
                <Input value={uploadForm.subject} onChange={(e) => setUploadForm({ ...uploadForm, subject: e.target.value })} className="mt-1" required />
              </div>
              <div>
                <Label className="text-xs text-gray-600">Chapter / Topic</Label>
                <Input value={uploadForm.chapter} onChange={(e) => setUploadForm({ ...uploadForm, chapter: e.target.value })} className="mt-1" />
              </div>
              <div>
                <Label className="text-xs text-gray-600">Type</Label>
                <select value={uploadForm.type} onChange={(e) => setUploadForm({ ...uploadForm, type: e.target.value as any })} className="w-full mt-1 border border-gray-200 rounded-lg px-3 py-2 text-sm bg-white">
                  <option value="notes">Notes</option>
                  <option value="video">Video</option>
                  <option value="assignment">Assignment</option>
                </select>
              </div>
              <div>
                <Label className="text-xs text-gray-600">Description</Label>
                <Input value={uploadForm.description} onChange={(e) => setUploadForm({ ...uploadForm, description: e.target.value })} className="mt-1" />
              </div>
              <div>
                <Label className="text-xs text-gray-600">URL (Google Drive / YouTube)</Label>
                <Input value={uploadForm.url} onChange={(e) => setUploadForm({ ...uploadForm, url: e.target.value })} placeholder="https://" className="mt-1" />
              </div>
              <div className="col-span-2 flex gap-3">
                <Button type="submit" className="bg-[#0c2340]" disabled={isPending}>{isPending ? "Submitting…" : "Submit for Review"}</Button>
                <Button type="button" variant="outline" onClick={() => setShowUpload(false)}>Cancel</Button>
              </div>
            </form>
          </div>
        )}

        {/* Filters */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-4 flex flex-wrap items-center gap-3">
          <div className="relative flex-1 min-w-48">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-300" />
            <Input value={searchQ} onChange={(e) => setSearchQ(e.target.value)} placeholder="Search resources…" className="pl-9 text-sm bg-gray-50 border-gray-100" />
          </div>
          <select value={stream} onChange={(e) => setStream(e.target.value)} className="border border-gray-200 rounded-lg px-3 py-2 text-sm bg-white">
            <option value="">All Streams</option>
            {streams.map((s) => <option key={s}>{s}</option>)}
          </select>
          <select value={semester} onChange={(e) => setSemester(e.target.value ? Number(e.target.value) : "")} className="border border-gray-200 rounded-lg px-3 py-2 text-sm bg-white">
            <option value="">All Semesters</option>
            {[1, 2, 3, 4, 5, 6, 7, 8].map((s) => <option key={s} value={s}>Sem {s}</option>)}
          </select>
        </div>

        {/* Resource grid */}
        {isLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {[1, 2, 3, 4, 5, 6].map((i) => <div key={i} className="h-36 bg-gray-100 animate-pulse rounded-2xl" />)}
          </div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-20 text-gray-300">
            <Library size={52} className="mx-auto mb-4 opacity-20" />
            <p className="text-sm font-medium">No resources found</p>
            <p className="text-xs mt-1">Be the first to contribute!</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {filtered.map((r) => (
              <div key={r.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all hover:-translate-y-0.5 p-5">
                <div className="flex items-start justify-between mb-3">
                  <div className={`p-2.5 rounded-xl ${typeColor[r.type]}`}>{typeIcon[r.type]}</div>
                  <span className={`flex items-center gap-1 text-[10px] font-semibold px-2 py-1 rounded-full ${statusBadge[r.status]}`}>
                    {statusIcon[r.status]} {r.status}
                  </span>
                </div>
                <h3 className="font-bold text-gray-900 text-sm mb-1 leading-tight">{r.title}</h3>
                {r.description && <p className="text-xs text-gray-400 mb-2 line-clamp-2">{r.description}</p>}
                <div className="text-[10px] text-gray-300 mb-3">
                  {r.stream} · Sem {r.semester} · {r.subject}{r.chapter ? ` · ${r.chapter}` : ""}
                </div>
                {r.url && (
                  <a href={r.url} target="_blank" rel="noopener noreferrer" className="text-xs text-[#0c2340] hover:text-blue-600 font-medium flex items-center gap-1 transition-colors">
                    Open Resource <ChevronRight size={12} />
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

