];

type GeneralInfo = {
  fullName: string; parentName: string; phone: string; email: string;
  collegeName: string; lastInstitute: string; caste: string; religion: string;
  yearlyIncome: string; aadharNo: string;
};
type AcademicInfo = {
  marks10th: string; marks12th: string; cgpa: string; sgpa: string;
  markcard10: string; markcard12: string;
};
type Documents = {
  aadharDoc: string; panDoc: string; bankStatement: string; admissionLetter: string;
};

