  marks10th: "", marks12th: "", cgpa: "", sgpa: "", markcard10: "", markcard12: "",
};
const emptyDocs: Documents = {
  aadharDoc: "", panDoc: "", bankStatement: "", admissionLetter: "",
};

function StepIndicator({ current }: { current: number }) {
  return (
    <div className="flex items-center gap-0 mb-8">
      {STEPS.map((step, i) => (
        <div key={i} className="flex items-center">
          <div className={`flex items-center gap-2 px-4 py-2.5 rounded-full text-sm font-semibold transition-all ${
            i < current ? "bg-emerald-100 text-emerald-700" :
            i === current ? "bg-[#0c2340] text-white shadow-md" :
            "bg-gray-100 text-gray-400"
          }`}>
            {i < current ? <CheckCircle size={14} /> : step.icon}
            <span className="hidden sm:block">{step.label}</span>
            <span className="sm:hidden text-xs">{i + 1}</span>
          </div>
          {i < STEPS.length - 1 && (
            <div className={`w-8 h-0.5 mx-1 ${i < current ? "bg-emerald-300" : "bg-gray-200"}`} />
          )}
        </div>
      ))}
    </div>
  );
}

