    <div>
      <Label className="text-xs text-gray-600 font-semibold">{label}</Label>
      {hint && <p className="text-[10px] text-gray-400 mb-1">{hint}</p>}
      <div className="mt-1 border-2 border-dashed border-gray-200 rounded-xl p-4 hover:border-[#0c2340]/30 transition-colors bg-gray-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-white border border-gray-200 flex items-center justify-center flex-shrink-0">
            <Upload size={14} className="text-gray-400" />
          </div>
          <div className="flex-1 min-w-0">
            <Input
              value={value}
              onChange={(e) => onChange(e.target.value)}
              placeholder="Paste Google Drive / cloud link"
              className="border-0 bg-transparent p-0 text-sm focus-visible:ring-0 placeholder:text-gray-300"
            />
          </div>
        </div>
        <p className="text-[10px] text-gray-300 mt-2 ml-11">Upload your document to Google Drive and paste the shareable link here</p>
      </div>
    </div>
  );
}

function ScholarshipContent() {
  const [step, setStep] = useState(0);
  const [general, setGeneral] = useState<GeneralInfo>(emptyGeneral);
  const [academic, setAcademic] = useState<AcademicInfo>(emptyAcademic);
  const [docs, setDocs] = useState<Documents>(emptyDocs);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  // Load saved application
  useEffect(() => {
    fetch("/api/scholarship/application", { credentials: "include" })
      .then((r) => r.json())
      .then((data) => {
        if (data) {
          setStep(Math.min((data.currentStep ?? 1) - 1, 3));
          if (data.generalInfo) setGeneral(data.generalInfo);
          if (data.academicInfo) setAcademic(data.academicInfo);
          if (data.documents) setDocs(data.documents);
        }
      })
      .catch(() => {});
  }, []);

  async function saveAndNext() {
    setSaving(true);
    try {
      await fetch("/api/scholarship/application", {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          step: step + 2,
          generalInfo: general,
          academicInfo: academic,
          documents: docs,
          submitted: step === 2,
        }),
      });
      setStep((s) => s + 1);
      if (step === 2) toast({ title: "Application submitted!", description: "Your scholarship application has been saved." });
    } finally {
      setSaving(false);
    }
  }

  const matchedScholarships = scholarships.filter((s) => {
    const income = parseInt(general.yearlyIncome.replace(/,/g, "")) || 0;
    const cat = general.caste.toLowerCase();
    const marks = parseFloat(academic.marks12th) || 0;
    const sgpa = parseFloat(academic.sgpa) || 0;
    if (income > s.criteria.maxIncome) return false;
    if (!s.criteria.categories.includes(cat) && cat) return false;
    if (marks < s.criteria.minMarks) return false;
    if (s.criteria.minSGPA && sgpa < s.criteria.minSGPA) return false;
    return true;
  });

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-student px-8 pt-8 pb-14">
        <div className="max-w-4xl mx-auto">
          <p className="text-blue-300 text-xs font-semibold uppercase tracking-wider mb-2">Financial Aid</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <Award size={22} /> Scholarship Application
          </h1>
          <p className="text-blue-200/70 text-sm mt-1">Complete your profile to discover matching scholarships</p>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-8 -mt-6 pb-10">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-8">
          <StepIndicator current={step} />

          {/* Step 0 — General Info */}
          {step === 0 && (
            <div>
              <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center">
                  <User size={18} className="text-blue-600" />
                </div>
                <div>
                  <h2 className="font-bold text-gray-900">General Information</h2>
                  <p className="text-xs text-gray-400">Personal and family details</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><Label className="text-xs text-gray-600 font-semibold">Full Name *</Label><Input value={general.fullName} onChange={(e) => setGeneral({ ...general, fullName: e.target.value })} className="mt-1" required /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Parent / Guardian Name *</Label><Input value={general.parentName} onChange={(e) => setGeneral({ ...general, parentName: e.target.value })} className="mt-1" required /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Mobile Number *</Label><Input value={general.phone} onChange={(e) => setGeneral({ ...general, phone: e.target.value })} placeholder="10-digit mobile" className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Email ID *</Label><Input type="email" value={general.email} onChange={(e) => setGeneral({ ...general, email: e.target.value })} className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">College Name</Label><Input value={general.collegeName} onChange={(e) => setGeneral({ ...general, collegeName: e.target.value })} className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Last Educational Institution *</Label><Input value={general.lastInstitute} onChange={(e) => setGeneral({ ...general, lastInstitute: e.target.value })} placeholder="School / PU college name" className="mt-1" /></div>
                <div>
                  <Label className="text-xs text-gray-600 font-semibold">Caste / Category *</Label>
                  <select value={general.caste} onChange={(e) => setGeneral({ ...general, caste: e.target.value })} className="w-full mt-1 border border-gray-200 rounded-lg px-3 py-2 text-sm bg-white">
                    <option value="">Select category</option>
                    <option value="general">General</option>
                    <option value="obc">OBC</option>
                    <option value="sc">SC</option>
                    <option value="st">ST</option>
                    <option value="ews">EWS</option>
                  </select>
                </div>
                <div><Label className="text-xs text-gray-600 font-semibold">Religion</Label><Input value={general.religion} onChange={(e) => setGeneral({ ...general, religion: e.target.value })} placeholder="e.g. Hindu, Muslim, Christian…" className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Annual Family Income (₹) *</Label><Input value={general.yearlyIncome} onChange={(e) => setGeneral({ ...general, yearlyIncome: e.target.value })} placeholder="e.g. 4,00,000" className="mt-1" /></div>
                <div>
                  <Label className="text-xs text-gray-600 font-semibold">Aadhaar Number (Demo)</Label>
                  <Input value={general.aadharNo} onChange={(e) => setGeneral({ ...general, aadharNo: e.target.value })} placeholder="XXXX XXXX XXXX" maxLength={14} className="mt-1" />
                  <p className="text-[10px] text-gray-300 mt-1">For demo purposes only — not stored securely</p>
                </div>
              </div>
              <div className="flex justify-end mt-6">
                <Button onClick={saveAndNext} className="bg-[#0c2340] px-6" disabled={saving || !general.fullName || !general.parentName || !general.yearlyIncome || !general.caste}>
                  {saving ? "Saving…" : "Continue"} <ChevronRight size={15} className="ml-1" />
                </Button>
              </div>
            </div>
          )}

          {/* Step 1 — Academic Details */}
          {step === 1 && (
            <div>
              <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center">
                  <BookOpen size={18} className="text-indigo-600" />
                </div>
                <div>
                  <h2 className="font-bold text-gray-900">Academic Details</h2>
                  <p className="text-xs text-gray-400">Your academic performance history</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 mb-6">
                <div><Label className="text-xs text-gray-600 font-semibold">10th Standard Marks (%) *</Label><Input type="number" min={0} max={100} value={academic.marks10th} onChange={(e) => setAcademic({ ...academic, marks10th: e.target.value })} placeholder="e.g. 85" className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">12th / PUC Marks (%) *</Label><Input type="number" min={0} max={100} value={academic.marks12th} onChange={(e) => setAcademic({ ...academic, marks12th: e.target.value })} placeholder="e.g. 78" className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Current CGPA</Label><Input type="number" min={0} max={10} step={0.01} value={academic.cgpa} onChange={(e) => setAcademic({ ...academic, cgpa: e.target.value })} placeholder="e.g. 8.15" className="mt-1" /></div>
                <div><Label className="text-xs text-gray-600 font-semibold">Current Semester SGPA</Label><Input type="number" min={0} max={10} step={0.01} value={academic.sgpa} onChange={(e) => setAcademic({ ...academic, sgpa: e.target.value })} placeholder="e.g. 8.42" className="mt-1" /></div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <FileUploadField label="10th Markcard *" value={academic.markcard10} onChange={(v) => setAcademic({ ...academic, markcard10: v })} hint="Upload scanned copy of your 10th markcard" />
                <FileUploadField label="12th / PUC Markcard *" value={academic.markcard12} onChange={(v) => setAcademic({ ...academic, markcard12: v })} hint="Upload scanned copy of your 12th or PUC markcard" />
              </div>
              <div className="flex justify-between mt-6">
                <Button variant="outline" onClick={() => setStep(0)} className="px-5"><ChevronLeft size={14} className="mr-1" />Back</Button>
                <Button onClick={saveAndNext} className="bg-[#0c2340] px-6" disabled={saving || !academic.marks10th || !academic.marks12th}>
                  {saving ? "Saving…" : "Continue"} <ChevronRight size={15} className="ml-1" />
                </Button>
              </div>
            </div>
          )}

          {/* Step 2 — Documents */}
          {step === 2 && (
            <div>
              <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center">
                  <FileText size={18} className="text-amber-600" />
                </div>
                <div>
                  <h2 className="font-bold text-gray-900">Document Upload</h2>
                  <p className="text-xs text-gray-400">Upload supporting documents as Google Drive links</p>
                </div>
              </div>
              <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 mb-6 flex items-start gap-3">
                <AlertCircle size={16} className="text-amber-600 flex-shrink-0 mt-0.5" />
                <p className="text-xs text-amber-700">Please upload documents to Google Drive, set sharing to "Anyone with the link", and paste the link below. This is a demo system — do not upload real sensitive documents.</p>
              </div>
              <div className="grid grid-cols-2 gap-5">
                <FileUploadField label="Aadhaar Card" value={docs.aadharDoc} onChange={(v) => setDocs({ ...docs, aadharDoc: v })} hint="Front and back scan / PDF" />
                <FileUploadField label="PAN Card" value={docs.panDoc} onChange={(v) => setDocs({ ...docs, panDoc: v })} hint="Clear scan of PAN card" />
                <FileUploadField label="Bank Passbook / Statement" value={docs.bankStatement} onChange={(v) => setDocs({ ...docs, bankStatement: v })} hint="Last 3 months statement" />
