                </div>
              ) : (
                <div className="mt-5 space-y-4">
                  {matchedScholarships.map((s) => (
                    <div key={s.name} className="bg-white border border-gray-100 rounded-xl p-5 shadow-sm hover:shadow-md transition-all">
                      <div className="flex items-start gap-4">
                        <div className={`flex-shrink-0 px-2.5 py-1 rounded-lg ${s.color} text-white text-xs font-bold`}>{s.badge}</div>
                        <div className="flex-1 min-w-0">
                          <h3 className="font-bold text-gray-900 text-sm mb-0.5">{s.name}</h3>
                          <p className="text-xs text-gray-500 mb-2">{s.desc}</p>
                          <div className="flex flex-wrap gap-2">
                            <span className="text-[10px] bg-gray-50 text-gray-500 px-2 py-1 rounded-full">Income ≤ ₹{(s.criteria.maxIncome / 100000).toFixed(0)}L</span>
                            {s.criteria.minMarks > 0 && <span className="text-[10px] bg-gray-50 text-gray-500 px-2 py-1 rounded-full">{s.criteria.minMarks}%+ in 12th</span>}
                            {s.criteria.minSGPA && <span className="text-[10px] bg-gray-50 text-gray-500 px-2 py-1 rounded-full">SGPA ≥ {s.criteria.minSGPA}</span>}
                          </div>
                        </div>
                        <a href={s.link} target="_blank" rel="noopener noreferrer" className="flex-shrink-0">
                          <Button size="sm" className="bg-[#0c2340] text-xs">
                            Apply <ExternalLink size={11} className="ml-1" />
                          </Button>
                        </a>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              <div className="flex items-center justify-between mt-6 pt-5 border-t border-gray-50">
                <Button variant="outline" onClick={() => setStep(0)} className="text-sm">Edit Application</Button>
                <div className="text-xs text-gray-400 flex items-center gap-1.5">
                  <CheckCircle size={12} className="text-emerald-500" />
                  Application saved successfully
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

