function RiskBadge({ level }: { level: string }) {
  const cfg: Record<string, { color: string; label: string }> = {
    low: { color: "bg-emerald-100 text-emerald-700", label: "Low Risk" },
    medium: { color: "bg-amber-100 text-amber-700", label: "Moderate Risk" },
    high: { color: "bg-orange-100 text-orange-700", label: "High Risk" },
    critical: { color: "bg-red-100 text-red-700", label: "Critical Risk" },
  };
  const c = cfg[level] ?? cfg.low;
  return <span className={`text-xs font-semibold px-2.5 py-1 rounded-full ${c.color}`}>{c.label}</span>;
}

function SeverityBar({ severity }: { severity: string }) {
  const colors: Record<string, string> = { critical: "bg-red-500", warning: "bg-amber-400", info: "bg-blue-400" };
  return <div className={`w-1 h-full rounded-full ${colors[severity] ?? colors.info} flex-shrink-0`} style={{ minHeight: 40 }} />;
}

