                    <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-emerald-900 inline-block" />CIE 2</span>
                  </div>
                </div>
              </div>
            )}

            {/* Subject-wise attendance detail */}
            {subjectRecords.length > 0 && (
