                          {att < 75 ? "Critical" : att < 85 ? "Warning" : "Good"}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Contact card */}
            <div className="bg-gradient-to-r from-emerald-900 to-emerald-800 rounded-2xl p-6 flex items-center justify-between">
              <div>
                <h3 className="font-bold text-white mb-1 flex items-center gap-2"><MessageSquare size={15} />Contact Proctor</h3>
                <p className="text-emerald-200/80 text-sm">Reach out to your child's proctor for guidance</p>
              </div>
              <Link href="/parent/chat">
                <button className="bg-white text-emerald-800 px-5 py-2.5 rounded-xl font-semibold text-sm hover:bg-emerald-50 transition-colors flex items-center gap-2">
