    approve({ id, data: { status } }, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getListResourcesQueryKey({ status: "pending" }) });
        queryClient.invalidateQueries({ queryKey: getListResourcesQueryKey({ status: "approved" }) });
