                </div>
                <div className="col-span-2 flex gap-3">
                  <Button type="submit" className="bg-rose-700 hover:bg-rose-800" disabled={uploading}>
                    <Upload size={14} className="mr-2" /> {uploading ? "Publishing…" : "Publish to StudyVault"}
