import { useState, useEffect } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ClipboardCheck, Check, X, Save, Users, CalendarDays, AlertCircle, CheckCircle } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const sections = ["CS-A", "CS-B", "EC-A", "EC-B", "ME-A", "CI-A", "IS-A"];
const subjects = [
  "Data Structures & Algorithms", "Database Management Systems", "Computer Networks",
  "Operating Systems", "Software Engineering", "Machine Learning",
];

interface Student {
  id: number; name: string; usn: string | null; section: string | null; semester: number | null;
}

interface AttendanceEntry {
  studentId: number;
  status: "present" | "absent";
}

function AttendanceContent() {
  const [section, setSection] = useState("CS-A");
  const [subject, setSubject] = useState(subjects[0]);
  const [semester, setSemester] = useState(5);
  const [sessionDate, setSessionDate] = useState(new Date().toISOString().slice(0, 10));
  const [students, setStudents] = useState<Student[]>([]);
  const [entries, setEntries] = useState<Record<number, "present" | "absent">>({});
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    setLoading(true);
    fetch(`/api/attendance/students?section=${encodeURIComponent(section)}&semester=${semester}`, { credentials: "include" })
      .then((r) => r.json())
      .then((data: Student[]) => {
        setStudents(data);
        // Default everyone to present
        const init: Record<number, "present" | "absent"> = {};
        data.forEach((s) => { init[s.id] = "present"; });
        setEntries(init);
        setSaved(false);
      })
      .catch(() => setStudents([]))
      .finally(() => setLoading(false));
  }, [section, semester]);

  function markAll(status: "present" | "absent") {
    const updated: Record<number, "present" | "absent"> = {};
    students.forEach((s) => { updated[s.id] = status; });
    setEntries(updated);
  }

  function toggle(id: number) {
    setEntries((prev) => ({ ...prev, [id]: prev[id] === "present" ? "absent" : "present" }));
  }

  async function saveAttendance() {
    setSaving(true);
    try {
      const payload = {
        subject,
        section,
        semester,
        sessionDate,
        entries: students.map((s) => ({ studentId: s.id, status: entries[s.id] ?? "present" })),
      };
      const res = await fetch("/api/attendance/sessions", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (!res.ok) throw new Error("Failed");
      setSaved(true);
      const present = Object.values(entries).filter((v) => v === "present").length;
      toast({ title: "Attendance saved", description: `${present}/${students.length} present. Subject % auto-updated.` });
    } catch {
      toast({ title: "Error", description: "Failed to save attendance.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  }

  const presentCount = Object.values(entries).filter((v) => v === "present").length;
  const absentCount = students.length - presentCount;
  const pct = students.length > 0 ? Math.round((presentCount / students.length) * 100) : 0;

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-faculty px-8 pt-8 pb-14">
        <div className="max-w-7xl mx-auto">
          <p className="text-rose-300 text-xs font-semibold uppercase tracking-wider mb-2">Class Management</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <ClipboardCheck size={22} /> Attendance Marking
          </h1>
          <p className="text-rose-200/70 text-sm mt-1">Mark attendance for a class session — percentages update automatically</p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 -mt-6 pb-10 space-y-5">
        {/* Session config */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <h2 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
            <CalendarDays size={16} className="text-rose-600" /> Session Details
          </h2>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div>
              <Label className="text-xs text-gray-500 font-semibold">Section *</Label>
              <select value={section} onChange={(e) => setSection(e.target.value)} className="w-full mt-1 border border-gray-200 rounded-lg px-3 py-2.5 text-sm bg-white">
                {sections.map((s) => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <Label className="text-xs text-gray-500 font-semibold">Semester *</Label>
              <select value={semester} onChange={(e) => setSemester(Number(e.target.value))} className="w-full mt-1 border border-gray-200 rounded-lg px-3 py-2.5 text-sm bg-white">
                {[1, 2, 3, 4, 5, 6, 7, 8].map((s) => <option key={s} value={s}>Semester {s}</option>)}
              </select>
            </div>
            <div>
              <Label className="text-xs text-gray-500 font-semibold">Subject *</Label>
              <select value={subject} onChange={(e) => setSubject(e.target.value)} className="w-full mt-1 border border-gray-200 rounded-lg px-3 py-2.5 text-sm bg-white">
                {subjects.map((s) => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <Label className="text-xs text-gray-500 font-semibold">Session Date *</Label>
              <Input type="date" value={sessionDate} onChange={(e) => setSessionDate(e.target.value)} className="mt-1" />
            </div>
          </div>
        </div>

        {/* Attendance marking */}
        {loading ? (
          <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-8 text-center">
            <div className="animate-pulse space-y-3">
              {[1, 2, 3].map((i) => <div key={i} className="h-14 bg-gray-100 rounded-xl" />)}
            </div>
          </div>
        ) : students.length === 0 ? (
          <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-12 text-center">
            <Users size={48} className="mx-auto mb-4 text-gray-200" />
            <p className="text-gray-400 text-sm font-medium">No students found in {section}</p>
            <p className="text-gray-300 text-xs mt-1">Check the section and semester selection</p>
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            {/* Summary bar */}
            <div className="px-6 py-4 border-b border-gray-50 flex items-center justify-between">
              <div className="flex items-center gap-6">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-emerald-100 flex items-center justify-center">
                    <Check size={14} className="text-emerald-600" />
                  </div>
                  <div>
                    <div className="text-sm font-bold text-gray-900">{presentCount}</div>
                    <div className="text-[10px] text-gray-400">Present</div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-red-100 flex items-center justify-center">
                    <X size={14} className="text-red-600" />
                  </div>
                  <div>
                    <div className="text-sm font-bold text-gray-900">{absentCount}</div>
                    <div className="text-[10px] text-gray-400">Absent</div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center ${pct >= 85 ? "bg-emerald-100" : pct >= 70 ? "bg-amber-100" : "bg-red-100"}`}>
                    <span className={`text-xs font-bold ${pct >= 85 ? "text-emerald-700" : pct >= 70 ? "text-amber-700" : "text-red-700"}`}>{pct}%</span>
                  </div>
                  <div>
                    <div className="text-sm font-bold text-gray-900">Class %</div>
                    <div className="text-[10px] text-gray-400">This session</div>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <Button size="sm" variant="outline" onClick={() => markAll("present")} className="text-emerald-700 border-emerald-200 hover:bg-emerald-50 text-xs">
                  <Check size={12} className="mr-1" /> All Present
                </Button>
                <Button size="sm" variant="outline" onClick={() => markAll("absent")} className="text-red-600 border-red-200 hover:bg-red-50 text-xs">
                  <X size={12} className="mr-1" /> All Absent
                </Button>
              </div>
            </div>

            {/* Student list */}
            <div className="divide-y divide-gray-50">
              {students.map((student, idx) => {
                const isPresent = entries[student.id] === "present";
                return (
                  <div
                    key={student.id}
                    className={`flex items-center gap-4 px-6 py-3.5 hover:bg-gray-50/50 cursor-pointer transition-colors ${!isPresent ? "bg-red-50/40" : ""}`}
                    onClick={() => toggle(student.id)}
                  >
                    <div className="text-xs text-gray-300 w-6 flex-shrink-0 font-mono">{String(idx + 1).padStart(2, "0")}</div>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 ${isPresent ? "bg-emerald-100 text-emerald-700" : "bg-red-100 text-red-700"}`}>
                      {student.name.charAt(0)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-semibold text-gray-900">{student.name}</div>
                      <div className="text-xs text-gray-400">{student.usn ?? "—"}</div>
                    </div>
                    <div
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-all ${isPresent ? "bg-emerald-100 text-emerald-700" : "bg-red-100 text-red-700"}`}
                    >
                      {isPresent ? <Check size={11} /> : <X size={11} />}
                      {isPresent ? "Present" : "Absent"}
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Save bar */}
            <div className="px-6 py-4 border-t border-gray-50 bg-gray-50/30 flex items-center justify-between">
              <div className="flex items-center gap-2 text-xs text-gray-400">
                <AlertCircle size={12} />
                Click a student to toggle presence · Subject attendance % updates automatically after saving
              </div>
              <div className="flex items-center gap-3">
                {saved && (
                  <span className="flex items-center gap-1 text-xs text-emerald-600 font-medium">
                    <CheckCircle size={12} /> Saved
                  </span>
                )}
                <Button onClick={saveAttendance} className="bg-rose-700 hover:bg-rose-800" disabled={saving || students.length === 0}>
                  <Save size={14} className="mr-2" />
                  {saving ? "Saving…" : "Save Attendance"}
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default function FacultyAttendance() {
  return (
    <RequireAuth allowedRoles={["faculty", "admin"]}>
      <PortalLayout theme="faculty">
        <AttendanceContent />
      </PortalLayout>
    </RequireAuth>
  );
}

import { useState } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import {
  useListProfiles, useGetAcademics, useUpdateAcademics, useGetSubjectRecords,
  getGetAcademicsQueryKey, getListProfilesQueryKey, getGetSubjectRecordsQueryKey
} from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Search, Save, GraduationCap, AlertTriangle, CheckCircle, BarChart2 } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from "recharts";

function AcademicsContent() {
  const [search, setSearch] = useState("");
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [editValues, setEditValues] = useState({ sgpa: "", cgpa: "", overallAttendance: "" });
  const queryClient = useQueryClient();
  const { toast } = useToast();

  const { data: profiles } = useListProfiles({ role: "student" }, {
    query: { queryKey: getListProfilesQueryKey({ role: "student" }) },
  });
  const { data: academics, isLoading: aLoading } = useGetAcademics(selectedId ?? 0, {
    query: { enabled: !!selectedId, queryKey: getGetAcademicsQueryKey(selectedId ?? 0) },
  });
  const { data: subjects } = useGetSubjectRecords(selectedId ?? 0, {
    query: { enabled: !!selectedId, queryKey: getGetSubjectRecordsQueryKey(selectedId ?? 0) },
  });
  const { mutate: update, isPending } = useUpdateAcademics();

  const filtered = (profiles ?? []).filter((p) =>
    p.name.toLowerCase().includes(search.toLowerCase()) || (p.usn ?? "").toLowerCase().includes(search.toLowerCase())
  );

  function selectStudent(id: number) {
    setSelectedId(id);
    setEditValues({ sgpa: "", cgpa: "", overallAttendance: "" });
  }

  function handleSave() {
    if (!selectedId) return;
    const body: any = {};
    if (editValues.sgpa) body.sgpa = Number(editValues.sgpa);
    if (editValues.cgpa) body.cgpa = Number(editValues.cgpa);
    if (editValues.overallAttendance) body.overallAttendance = Number(editValues.overallAttendance);

    update({ studentId: selectedId, data: body }, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getGetAcademicsQueryKey(selectedId) });
        setEditValues({ sgpa: "", cgpa: "", overallAttendance: "" });
        toast({ title: "Updated", description: "Academic record saved successfully." });
      },
      onError: () => toast({ title: "Error", description: "Failed to update.", variant: "destructive" }),
    });
  }

  const attChartData = (subjects ?? []).map((s) => ({
    name: s.subject.split(" ")[0],
    value: Number(s.attendance),
  }));

  const marksData = (subjects ?? []).map((s) => ({
    name: s.subject.split(" ")[0],
    CIE1: Number(s.cie1 ?? 0),
    CIE2: Number(s.cie2 ?? 0),
  }));

  const selectedProfile = filtered.find((p) => p.id === selectedId);

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-faculty px-8 pt-8 pb-14">
        <div className="max-w-7xl mx-auto">
          <p className="text-rose-300 text-xs font-semibold uppercase tracking-wider mb-2">Academic Management</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <GraduationCap size={22} /> Student Academics
          </h1>
          <p className="text-rose-200/70 text-sm mt-1">Edit marks and view subject-wise performance charts</p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 -mt-6 pb-10">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Student list */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-4 border-b border-gray-50">
              <div className="relative">
                <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-300" />
                <Input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search by name or USN…" className="pl-9 text-sm bg-gray-50 border-gray-100" />
              </div>
            </div>
            <div className="overflow-y-auto max-h-[520px] divide-y divide-gray-50">
              {filtered.map((p) => {
                const isSelected = selectedId === p.id;
                return (
                  <button key={p.id} onClick={() => selectStudent(p.id)}
                    className={`w-full flex items-center gap-3 px-4 py-3.5 text-left hover:bg-gray-50 transition-colors ${isSelected ? "bg-rose-50 border-l-[3px] border-rose-600" : ""}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 ${isSelected ? "bg-rose-600 text-white" : "bg-rose-100 text-rose-700"}`}>
                      {p.name.charAt(0)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm text-gray-900 truncate">{p.name}</div>
                      <div className="text-xs text-gray-400">{p.usn ?? "—"} · Sem {p.semester ?? "—"}</div>
                    </div>
                    {isSelected && <div className="w-1.5 h-1.5 rounded-full bg-rose-500 flex-shrink-0" />}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Edit panel */}
          <div className="lg:col-span-2 space-y-5">
            {!selectedId ? (
              <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-16 text-center">
                <Search size={44} className="mx-auto mb-4 text-gray-200" />
                <p className="text-gray-400 text-sm font-medium">Select a student to view and edit their records</p>
              </div>
            ) : aLoading ? (
              <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-8 animate-pulse">
                <div className="h-5 bg-gray-100 rounded w-1/3 mb-4" />
                <div className="grid grid-cols-3 gap-3">{[1, 2, 3].map((i) => <div key={i} className="h-16 bg-gray-100 rounded-xl" />)}</div>
              </div>
            ) : (
              <>
                {/* Student overview */}
                <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                  <div className="flex items-center gap-3 mb-5">
                    <div className="w-10 h-10 rounded-xl bg-rose-100 text-rose-700 font-bold text-lg flex items-center justify-center">
                      {selectedProfile?.name?.charAt(0) ?? "?"}
                    </div>
                    <div>
                      <h2 className="font-bold text-gray-900">{selectedProfile?.name}</h2>
                      <p className="text-xs text-gray-400">{selectedProfile?.usn ?? "—"} · Section {selectedProfile?.section ?? "—"} · Sem {selectedProfile?.semester ?? "—"}</p>
                    </div>
                  </div>

                  {/* Current values */}
                  <div className="grid grid-cols-3 gap-4 mb-6">
                    {[
                      { label: "SGPA", value: academics ? Number(academics.sgpa).toFixed(2) : "—", color: "bg-blue-50 text-blue-700" },
                      { label: "CGPA", value: academics ? Number(academics.cgpa).toFixed(2) : "—", color: "bg-violet-50 text-violet-700" },
                      { label: "Attendance", value: academics ? `${Number(academics.overallAttendance).toFixed(1)}%` : "—", color: Number(academics?.overallAttendance ?? 100) < 85 ? "bg-red-50 text-red-700" : "bg-emerald-50 text-emerald-700" },
                    ].map((stat) => (
                      <div key={stat.label} className={`${stat.color} rounded-xl p-4 text-center`}>
                        <p className="text-xs font-medium opacity-70 mb-1">{stat.label}</p>
                        <p className="text-2xl font-bold">{stat.value}</p>
                      </div>
                    ))}
                  </div>

                  {/* Edit fields */}
                  <div className="grid grid-cols-3 gap-4 mb-4">
                    <div>
                      <Label className="text-xs text-gray-500 font-semibold">Update SGPA</Label>
                      <Input type="number" step="0.01" min="0" max="10" value={editValues.sgpa}
                        onChange={(e) => setEditValues({ ...editValues, sgpa: e.target.value })}
                        placeholder={academics ? Number(academics.sgpa).toFixed(2) : "0.00"} className="mt-1" />
                    </div>
                    <div>
                      <Label className="text-xs text-gray-500 font-semibold">Update CGPA</Label>
                      <Input type="number" step="0.01" min="0" max="10" value={editValues.cgpa}
                        onChange={(e) => setEditValues({ ...editValues, cgpa: e.target.value })}
                        placeholder={academics ? Number(academics.cgpa).toFixed(2) : "0.00"} className="mt-1" />
                    </div>
                    <div>
                      <Label className="text-xs text-gray-500 font-semibold">Overall Attendance (%)</Label>
                      <Input type="number" step="0.1" min="0" max="100" value={editValues.overallAttendance}
                        onChange={(e) => setEditValues({ ...editValues, overallAttendance: e.target.value })}
                        placeholder={academics ? Number(academics.overallAttendance).toFixed(1) : "0"} className="mt-1" />
                    </div>
                  </div>
                  <p className="text-xs text-gray-400 mb-4">Leave blank to keep current values. Note: Attendance auto-updates via the Attendance page when you mark classes.</p>
                  <Button onClick={handleSave} className="bg-rose-700 hover:bg-rose-800" disabled={isPending || (!editValues.sgpa && !editValues.cgpa && !editValues.overallAttendance)}>
                    <Save size={14} className="mr-2" /> {isPending ? "Saving…" : "Save Changes"}
                  </Button>
                </div>

                {/* Charts */}
                {(subjects?.length ?? 0) > 0 && (
                  <div className="grid grid-cols-2 gap-5">
                    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
                      <h3 className="font-bold text-gray-900 text-sm mb-3 flex items-center gap-2">
                        <CheckCircle size={13} className="text-emerald-500" /> Subject Attendance
                      </h3>
                      <ResponsiveContainer width="100%" height={150}>
                        <BarChart data={attChartData} barSize={20} margin={{ top: 4, right: 4, left: -22, bottom: 0 }}>
                          <XAxis dataKey="name" tick={{ fontSize: 9, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                          <YAxis domain={[0, 100]} tick={{ fontSize: 9, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                          <Tooltip formatter={(v: any) => [`${Number(v).toFixed(1)}%`, "Attendance"]} cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                          <Bar dataKey="value" radius={[5, 5, 0, 0]}>
                            {attChartData.map((e, i) => <Cell key={i} fill={e.value < 75 ? "#ef4444" : e.value < 85 ? "#f59e0b" : "#10b981"} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                    </div>
                    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
                      <h3 className="font-bold text-gray-900 text-sm mb-3 flex items-center gap-2">
                        <BarChart2 size={13} className="text-blue-500" /> CIE Scores
                      </h3>
                      <ResponsiveContainer width="100%" height={150}>
                        <BarChart data={marksData} barSize={10} barGap={2} margin={{ top: 4, right: 4, left: -22, bottom: 0 }}>
                          <XAxis dataKey="name" tick={{ fontSize: 9, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                          <YAxis domain={[0, 20]} tick={{ fontSize: 9, fill: "#9ca3af" }} axisLine={false} tickLine={false} />
                          <Tooltip cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                          <Bar dataKey="CIE1" fill="#f43f5e" radius={[4, 4, 0, 0]} name="CIE 1" />
                          <Bar dataKey="CIE2" fill="#9f1239" radius={[4, 4, 0, 0]} name="CIE 2" />
                        </BarChart>
                      </ResponsiveContainer>
                    </div>
                  </div>
                )}

                {/* Subject table */}
                {(subjects?.length ?? 0) > 0 && (
                  <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
                    <div className="px-5 py-4 border-b border-gray-50">
                      <h3 className="font-bold text-gray-900 text-sm">Subject-wise Records</h3>
                    </div>
                    <div className="overflow-x-auto">
                      <table className="w-full text-sm">
                        <thead>
                          <tr className="bg-gray-50/80">
                            <th className="px-4 py-2.5 text-left text-[11px] font-semibold text-gray-400 uppercase tracking-wider">Subject</th>
                            <th className="px-3 py-2.5 text-center text-[11px] font-semibold text-gray-400 uppercase tracking-wider">Att%</th>
                            <th className="px-3 py-2.5 text-center text-[11px] font-semibold text-gray-400 uppercase tracking-wider">CIE1</th>
                            <th className="px-3 py-2.5 text-center text-[11px] font-semibold text-gray-400 uppercase tracking-wider">CIE2</th>
                            <th className="px-3 py-2.5 text-center text-[11px] font-semibold text-gray-400 uppercase tracking-wider">Lab</th>
                            <th className="px-3 py-2.5 text-center text-[11px] font-semibold text-gray-400 uppercase tracking-wider">SEE</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                          {subjects?.map((s) => {
                            const att = Number(s.attendance);
                            return (
                              <tr key={s.id} className="hover:bg-gray-50/50 transition-colors">
                                <td className="px-4 py-3 font-medium text-gray-900 text-xs">{s.subject}</td>
                                <td className="px-3 py-3 text-center">
                                  <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${att < 75 ? "bg-red-100 text-red-700" : att < 85 ? "bg-amber-100 text-amber-700" : "bg-emerald-100 text-emerald-700"}`}>{att.toFixed(1)}%</span>
                                </td>
                                {[s.cie1, s.cie2, s.lab, s.see].map((v, i) => (
                                  <td key={i} className="px-3 py-3 text-center text-xs font-medium text-gray-700">{v != null ? Number(v).toFixed(0) : <span className="text-gray-200">—</span>}</td>
                                ))}
                              </tr>
                            );
                          })}
                        </tbody>
                      </table>
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default function FacultyAcademics() {
  return (
    <RequireAuth allowedRoles={["faculty", "admin"]}>
      <PortalLayout theme="faculty">
        <AcademicsContent />
      </PortalLayout>
    </RequireAuth>
  );
}

