import { Switch, Route, Router as WouterRouter } from "wouter";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { AuthProvider } from "@/contexts/AuthContext";
import { TenantProvider } from "@/contexts/TenantContext";
import NotFound from "@/pages/not-found";
import Landing from "@/pages/Landing";
import Login from "@/pages/Login";
import StudentDashboard from "@/pages/student/Dashboard";
import StudentAcademics from "@/pages/student/Academics";
import StudentScholarship from "@/pages/student/Scholarship";
import StudentGrievance from "@/pages/student/Grievance";
import StudentTimetable from "@/pages/student/Timetable";
import StudentNotes from "@/pages/student/Notes";
import ParentDashboard from "@/pages/parent/Dashboard";
import ParentChat from "@/pages/parent/Chat";
import FacultyDashboard from "@/pages/faculty/Dashboard";
import FacultyStudents from "@/pages/faculty/Students";
import FacultyAcademics from "@/pages/faculty/Academics";
import FacultyNotes from "@/pages/faculty/Notes";
import FacultyTimetable from "@/pages/faculty/Timetable";
import FacultyAttendance from "@/pages/faculty/Attendance";

const queryClient = new QueryClient({
  defaultOptions: {
    queries: { refetchOnWindowFocus: false, retry: 1 },
  },
});

function Router() {
  return (
    <Switch>
      <Route path="/" component={Landing} />
      <Route path="/login" component={Login} />
      <Route path="/student" component={StudentDashboard} />
      <Route path="/student/academics" component={StudentAcademics} />
      <Route path="/student/scholarship" component={StudentScholarship} />
      <Route path="/student/grievance" component={StudentGrievance} />
      <Route path="/student/timetable" component={StudentTimetable} />
      <Route path="/student/notes" component={StudentNotes} />
      <Route path="/parent" component={ParentDashboard} />
      <Route path="/parent/chat" component={ParentChat} />
      <Route path="/faculty" component={FacultyDashboard} />
      <Route path="/faculty/students" component={FacultyStudents} />
      <Route path="/faculty/academics" component={FacultyAcademics} />
      <Route path="/faculty/attendance" component={FacultyAttendance} />
      <Route path="/faculty/notes" component={FacultyNotes} />
      <Route path="/faculty/timetable" component={FacultyTimetable} />
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TenantProvider>
        <TooltipProvider>
          <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
            <AuthProvider>
              <Router />
            </AuthProvider>
          </WouterRouter>
          <Toaster />
        </TooltipProvider>
      </TenantProvider>
    </QueryClientProvider>
  );
}

export default App;

import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { useGetFacultyDashboard, getGetFacultyDashboardQueryKey } from "@workspace/api-client-react";
import { Users, AlertTriangle, TrendingUp, BookOpen, MessageSquare, BarChart2, ClipboardCheck, ChevronRight, Library } from "lucide-react";
import { Link } from "wouter";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from "recharts";

function FacultyDashboardContent() {
  const { data, isLoading } = useGetFacultyDashboard({
    query: { queryKey: getGetFacultyDashboardQueryKey() },
  });

  if (isLoading) {
    return (
      <div className="min-h-screen">
        <div className="page-header-faculty px-8 pt-8 pb-14">
          <div className="max-w-7xl mx-auto">
            <div className="h-8 bg-white/10 rounded-xl w-1/3 animate-pulse mb-2" />
            <div className="h-5 bg-white/10 rounded w-1/4 animate-pulse" />
          </div>
        </div>
        <div className="max-w-7xl mx-auto px-8 -mt-6 pb-10">
          <div className="grid grid-cols-5 gap-4 mb-6">
            {[1,2,3,4,5].map((i) => <div key={i} className="h-28 bg-gray-200 animate-pulse rounded-2xl" />)}
          </div>
          <div className="grid grid-cols-2 gap-6">
            <div className="h-64 bg-gray-200 animate-pulse rounded-2xl" />
            <div className="h-64 bg-gray-200 animate-pulse rounded-2xl" />
          </div>
        </div>
      </div>
    );
  }

  const greeting = new Date().getHours() < 12 ? "Good morning" : new Date().getHours() < 17 ? "Good afternoon" : "Good evening";
  const firstName = data?.profile.name?.split(" ").find((w) => w.length > 2) ?? data?.profile.name;

  const attendanceSummary = data?.attendanceSummary ?? [];
  const chartData = attendanceSummary.map((s) => ({
    name: s.section,
    attendance: Number(s.averageAttendance),
  }));

  const stats = [
    { label: "Total Students", value: data?.totalStudents ?? 0, icon: <Users size={18} />, color: "from-blue-600 to-blue-800", href: "/faculty/students" },
    { label: "At Risk", value: data?.atRiskCount ?? 0, icon: <AlertTriangle size={18} />, color: "from-red-600 to-rose-800", href: "/faculty/students" },
    { label: "High Performers", value: data?.highPerformersCount ?? 0, icon: <TrendingUp size={18} />, color: "from-emerald-600 to-emerald-800", href: "/faculty/students" },
    { label: "Pending Reviews", value: data?.pendingResourcesCount ?? 0, icon: <BookOpen size={18} />, color: "from-amber-600 to-amber-800", href: "/faculty/notes" },
    { label: "Open Grievances", value: data?.openGrievancesCount ?? 0, icon: <MessageSquare size={18} />, color: "from-violet-600 to-violet-800" },
  ];

  const actions = [
    { href: "/faculty/attendance", label: "Mark Attendance", desc: "Record today's class attendance", icon: <ClipboardCheck size={16} className="text-rose-600" /> },
    { href: "/faculty/academics", label: "Update Marks", desc: "Edit CIE, SGPA, CGPA records", icon: <BarChart2 size={16} className="text-blue-600" /> },
    { href: "/faculty/notes", label: "StudyVault", desc: `${data?.pendingResourcesCount ?? 0} resources pending review`, icon: <Library size={16} className="text-amber-600" /> },
    { href: "/faculty/students", label: "Student Roster", desc: "View all student profiles", icon: <Users size={16} className="text-emerald-600" /> },
    { href: "/faculty/timetable", label: "Timetable", desc: "Manage class schedule", icon: <MessageSquare size={16} className="text-violet-600" /> },
  ];

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-faculty px-8 pt-8 pb-16">
        <div className="max-w-7xl mx-auto flex items-start justify-between">
          <div>
            <p className="text-rose-300 text-xs font-semibold uppercase tracking-wider mb-2">{greeting}</p>
            <h1 className="text-3xl font-bold text-white mb-2">
              Dr. {firstName} 👋
            </h1>
            <p className="text-rose-200/70 text-sm">
              {data?.profile.section ? `Section ${data.profile.section} · ` : ""}RNSIT Faculty Portal
            </p>
          </div>
          <img src="/rnsit-logo.png" alt="RNSIT" className="w-14 h-14 rounded-xl object-cover opacity-70 hidden md:block" />
        </div>

        {/* Stat pills */}
        <div className="max-w-7xl mx-auto grid grid-cols-5 gap-4 mt-8">
          {stats.map((s) => {
            const content = (
              <div className={`bg-gradient-to-br ${s.color} rounded-2xl p-5 text-white shadow-sm hover:shadow-md transition-all hover:-translate-y-0.5 cursor-pointer`}>
                <div className="flex items-center justify-between mb-3">
                  <div className="w-8 h-8 bg-white/20 rounded-lg flex items-center justify-center">{s.icon}</div>
                  {s.href && <ChevronRight size={13} className="text-white/40" />}
                </div>
                <div className="text-3xl font-bold">{s.value}</div>
                <div className="text-white/70 text-xs mt-1">{s.label}</div>
              </div>
            );
            return s.href ? (
              <Link key={s.label} href={s.href} className="block">{content}</Link>
            ) : (
              <div key={s.label}>{content}</div>
            );
          })}
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 -mt-6 pb-10">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
          {/* Attendance chart */}
          <div className="lg:col-span-3 bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <div className="flex items-center justify-between mb-5">
              <div>
                <h2 className="font-bold text-gray-900 flex items-center gap-2">
                  <BarChart2 size={16} className="text-rose-600" /> Section-wise Attendance
                </h2>
                <p className="text-xs text-gray-400 mt-0.5">Average attendance % across all sections</p>
              </div>
              <Link href="/faculty/attendance" className="text-xs text-rose-700 hover:text-rose-800 font-semibold flex items-center gap-1">
                Mark Attendance <ChevronRight size={12} />
              </Link>
            </div>
            {chartData.length > 0 ? (
              <>
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={chartData} barSize={40} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
                    <XAxis dataKey="name" tick={{ fontSize: 11, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                    <YAxis domain={[0, 100]} tick={{ fontSize: 11, fill: "#6b7280" }} axisLine={false} tickLine={false} />
                    <Tooltip formatter={(v: any) => [`${Number(v).toFixed(1)}%`, "Avg Attendance"]} cursor={{ fill: "rgba(0,0,0,0.03)" }} />
                    <Bar dataKey="attendance" radius={[6, 6, 0, 0]}>
                      {chartData.map((entry, i) => (
                        <Cell key={i} fill={entry.attendance < 85 ? "#ef4444" : "#be123c"} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
                <div className="flex items-center gap-4 mt-3 text-[10px] text-gray-400">
                  <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-rose-700 inline-block" />≥85% On track</span>
                  <span className="flex items-center gap-1"><span className="w-2.5 h-2.5 rounded-sm bg-red-500 inline-block" />&lt;85% Needs attention</span>
                </div>
              </>
            ) : (
              <div className="text-center py-12 text-gray-200 border-2 border-dashed border-gray-100 rounded-xl">
                <BarChart2 size={40} className="mx-auto mb-3 opacity-30" />
                <p className="text-sm text-gray-400">No attendance data available yet</p>
                <p className="text-xs text-gray-300 mt-1">Use Attendance Marking to record class sessions</p>
              </div>
            )}
          </div>

          {/* Quick actions */}
          <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-gray-100 p-5">
            <h2 className="font-bold text-gray-900 mb-4 text-sm">Quick Actions</h2>
            <div className="space-y-1.5">
              {actions.map((item) => (
                <Link key={item.href} href={item.href} className="flex items-center gap-3 p-3 rounded-xl hover:bg-gray-50 transition-colors group">
                  <div className="w-9 h-9 rounded-xl bg-gray-100 group-hover:bg-white flex items-center justify-center flex-shrink-0 transition-colors shadow-none group-hover:shadow-sm">
                    {item.icon}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="font-semibold text-gray-900 text-sm">{item.label}</div>
                    <div className="text-xs text-gray-400 truncate">{item.desc}</div>
                  </div>
                  <ChevronRight size={14} className="text-gray-200 group-hover:text-gray-400 transition-colors flex-shrink-0" />
                </Link>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function FacultyDashboard() {
  return (
    <RequireAuth allowedRoles={["faculty", "admin"]}>
      <PortalLayout theme="faculty">
        <FacultyDashboardContent />
      </PortalLayout>
    </RequireAuth>
  );
}

