import { useState, useRef, useEffect } from "react";
import { RequireAuth, useAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { useListProctorMessages, useSendProctorMessage, getListProctorMessagesQueryKey } from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Send, MessageSquare, Wifi, User } from "lucide-react";

function ChatContent() {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const [message, setMessage] = useState("");
  const bottomRef = useRef<HTMLDivElement>(null);

  // Poll every 3 seconds for real-time updates
  const { data: messages, isLoading } = useListProctorMessages({
    query: {
      queryKey: getListProctorMessagesQueryKey(),
      refetchInterval: 3000,
    },
  });

  const { mutate: send, isPending } = useSendProctorMessage();

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  function handleSend(e: React.FormEvent) {
    e.preventDefault();
    if (!message.trim()) return;
    send(
      { data: { receiverId: user?.proctorId ?? 0, message: message.trim() } },
      {
        onSuccess: () => {
          queryClient.invalidateQueries({ queryKey: getListProctorMessagesQueryKey() });
          setMessage("");
        },
      }
    );
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (message.trim()) {
        handleSend(e as any);
      }
    }
  }

  // Group messages by date
  const groupedMessages = (messages ?? []).reduce<Record<string, typeof messages>>((acc, msg) => {
    const day = new Date(msg.createdAt).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });
    if (!acc[day]) acc[day] = [];
    acc[day]!.push(msg);
    return acc;
  }, {});

  return (
    <div className="min-h-screen">
      {/* Header */}
      <div className="page-header-parent px-8 pt-8 pb-14">
        <div className="max-w-4xl mx-auto">
          <p className="text-emerald-300 text-xs font-semibold uppercase tracking-wider mb-2">Secure Messaging</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <MessageSquare size={22} /> Proctor Chat
          </h1>
          <p className="text-emerald-200/70 text-sm mt-1">Direct channel with your child's assigned mentor</p>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-8 -mt-6 pb-10">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex flex-col" style={{ height: "72vh" }}>
          {/* Chat header */}
          <div className="px-5 py-4 border-b border-gray-50 flex items-center gap-3 bg-white">
            <div className="w-10 h-10 bg-emerald-100 rounded-xl flex items-center justify-center font-bold text-emerald-700 text-sm flex-shrink-0">
              DM
            </div>
            <div className="flex-1">
              <div className="font-bold text-gray-900 text-sm">Proctor / Mentor Faculty</div>
              <div className="flex items-center gap-1.5 text-xs text-gray-400">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                Live — updates every 3 seconds
              </div>
            </div>
            <div className="flex items-center gap-1.5 text-xs text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-full">
              <Wifi size={11} />
              <span>Live Chat</span>
            </div>
          </div>

          {/* Messages area */}
          <div className="flex-1 overflow-y-auto p-5 space-y-4 bg-gray-50/30">
            {isLoading ? (
              <div className="flex flex-col items-center justify-center h-full gap-3 text-gray-300">
                <div className="animate-spin w-6 h-6 border-2 border-emerald-200 border-t-emerald-600 rounded-full" />
                <p className="text-sm">Loading messages…</p>
              </div>
            ) : Object.keys(groupedMessages).length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-center">
                <div className="w-16 h-16 rounded-2xl bg-emerald-50 flex items-center justify-center mb-4">
                  <MessageSquare size={28} className="text-emerald-400" />
                </div>
                <p className="font-semibold text-gray-400 text-sm">No messages yet</p>
                <p className="text-gray-300 text-xs mt-1">Start a conversation with your child's proctor</p>
              </div>
            ) : (
              Object.entries(groupedMessages).map(([day, dayMessages]) => (
                <div key={day}>
                  {/* Date separator */}
                  <div className="flex items-center gap-3 my-4">
                    <div className="flex-1 h-px bg-gray-100" />
                    <span className="text-[10px] font-semibold text-gray-300 uppercase tracking-wider px-2">{day}</span>
                    <div className="flex-1 h-px bg-gray-100" />
                  </div>

                  <div className="space-y-2">
                    {dayMessages?.map((msg) => {
                      const isMine = msg.senderId === user?.id;
                      return (
                        <div key={msg.id} className={`flex items-end gap-2 ${isMine ? "justify-end" : "justify-start"}`}>
                          {!isMine && (
                            <div className="w-7 h-7 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-700 text-xs font-bold flex-shrink-0 mb-1">
                              <User size={12} />
                            </div>
                          )}
                          <div className={`max-w-sm ${isMine ? "items-end" : "items-start"} flex flex-col`}>
                            <div className={`px-4 py-2.5 rounded-2xl text-sm leading-relaxed ${
                              isMine
                                ? "bg-emerald-800 text-white rounded-br-sm shadow-sm"
                                : "bg-white text-gray-800 rounded-bl-sm shadow-sm border border-gray-100"
                            }`}>
                              <p>{msg.message}</p>
                            </div>
                            <p className={`text-[10px] mt-1 px-1 ${isMine ? "text-gray-400" : "text-gray-300"}`}>
                              {new Date(msg.createdAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
                            </p>
                          </div>
                          {isMine && (
                            <div className="w-7 h-7 rounded-full bg-emerald-800 flex items-center justify-center text-white text-xs font-bold flex-shrink-0 mb-5">
                              {user?.name?.charAt(0) ?? "P"}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))
            )}
            <div ref={bottomRef} />
          </div>

          {/* Input area */}
          <div className="border-t border-gray-100 bg-white p-4">
            <form onSubmit={handleSend} className="flex gap-2">
              <Input
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Type a message… (Enter to send)"
                className="flex-1 bg-gray-50 border-gray-100 rounded-xl text-sm"
                autoComplete="off"
              />
              <Button
                type="submit"
                className="bg-emerald-800 hover:bg-emerald-700 rounded-xl w-11 h-10 p-0 flex-shrink-0"
                disabled={isPending || !message.trim()}
              >
                {isPending ? (
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <Send size={15} />
                )}
              </Button>
            </form>
            <p className="text-[10px] text-gray-300 mt-2 text-center">Messages are visible to both the parent and the assigned faculty proctor</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function ParentChat() {
  return (
    <RequireAuth allowedRoles={["parent"]}>
      <PortalLayout theme="parent">
        <ChatContent />
      </PortalLayout>
    </RequireAuth>
  );
}

import app from "./app";
import { logger } from "./lib/logger";
import { seedDemoDataIfEmpty } from "./lib/demo-seed";

const rawPort = process.env["PORT"];

if (!rawPort) {
  throw new Error(
    "PORT environment variable is required but was not provided.",
  );
}

const port = Number(rawPort);

if (Number.isNaN(port) || port <= 0) {
  throw new Error(`Invalid PORT value: "${rawPort}"`);
}

// Auto-seed demo data if the database is empty (runs on every cold start)
seedDemoDataIfEmpty().then(() => {
  app.listen(port, (err) => {
    if (err) {
      logger.error({ err }, "Error listening on port");
      process.exit(1);
    }
    logger.info({ port }, "Server listening");
  });
});

