import { pgTable, serial, text, integer, boolean, timestamp, pgEnum } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";

export const roleEnum = pgEnum("role", ["student", "parent", "faculty", "admin"]);

export const profilesTable = pgTable("profiles", {
  id: serial("id").primaryKey(),
  email: text("email").notNull().unique(),
  passwordHash: text("password_hash").notNull(),
  name: text("name").notNull(),
  role: roleEnum("role").notNull().default("student"),
  usn: text("usn"),
  section: text("section"),
  semester: integer("semester"),
  batchPreference: text("batch_preference"),
  isCr: boolean("is_cr").notNull().default(false),
  proctorId: integer("proctor_id"),
  phone: text("phone"),
  branch: text("branch").default("Computer Science"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

export const insertProfileSchema = createInsertSchema(profilesTable).omit({ id: true, createdAt: true });
export type InsertProfile = z.infer<typeof insertProfileSchema>;
export type Profile = typeof profilesTable.$inferSelect;

export const parentStudentTable = pgTable("parent_student", {
  id: serial("id").primaryKey(),
  parentId: integer("parent_id").notNull(),
  studentId: integer("student_id").notNull(),
});

import { Router } from "express";
import twilio from "twilio";
import { db, profilesTable, subjectRecordsTable, parentStudentTable } from "@workspace/db";
import { eq, avg } from "drizzle-orm";

const router = Router();

function getTwilioClient() {
  const sid = process.env.TWILIO_ACCOUNT_SID;
  const token = process.env.TWILIO_AUTH_TOKEN;
  if (!sid || !token) throw new Error("Twilio credentials not configured");
  return twilio(sid, token);
}

function getBaseUrl(req: any): string {
  const domains = process.env.REPLIT_DOMAINS;
  if (domains) return `https://${domains.split(",")[0]}`;
  const devDomain = process.env.REPLIT_DEV_DOMAIN;
  if (devDomain) return `https://${devDomain}`;
  return `${req.protocol}://${req.get("host")}`;
}

// TwiML for the main English message with IVR
router.get("/twiml", (req, res) => {
  res.setHeader("Content-Type", "text/xml");
  const studentName = req.query.studentName ?? "the student";
  const usn = req.query.usn ?? "unknown";
  const branch = req.query.branch ?? "your";
  const base = getBaseUrl(req);
  const langUrl = `${base}/api/alerts/twiml/language?studentName=${encodeURIComponent(String(studentName))}&usn=${encodeURIComponent(String(usn))}&branch=${encodeURIComponent(String(branch))}`;

  res.send(`<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Gather numDigits="1" action="${langUrl}" method="POST" timeout="8">
    <Say language="en-IN" voice="Polly.Aditi">
      Greetings from R N S Institute of Technology, Bengaluru.
      This is an automated notification for the parents of ${studentName},
      U S N ${usn}, from the ${branch} department.
      Your child's current classroom attendance has dropped below 75 percent
      and internal evaluation marks are below 60 percent, falling to an unsatisfactory level.
      Please take immediate measures to correct this.
      If this trend continues, you will be formally called to the college campus
      for a mandatory evaluation with the branch proctor and the Head of the Department.
      To hear this message in Kannada, press 1.
      For Hindi, press 2.
      To repeat this message, press star.
      Thank you.
    </Say>
  </Gather>
  <Redirect>${base}/api/alerts/twiml?studentName=${encodeURIComponent(String(studentName))}&amp;usn=${encodeURIComponent(String(usn))}&amp;branch=${encodeURIComponent(String(branch))}</Redirect>
</Response>`);
});

// TwiML for language selection
router.post("/twiml/language", (req, res) => {
  res.setHeader("Content-Type", "text/xml");
  const digit = req.body.Digits ?? "";
  const studentName = req.query.studentName ?? "the student";
  const usn = req.query.usn ?? "unknown";
  const branch = req.query.branch ?? "your";
  const base = getBaseUrl(req);
  const mainUrl = `${base}/api/alerts/twiml?studentName=${encodeURIComponent(String(studentName))}&usn=${encodeURIComponent(String(usn))}&branch=${encodeURIComponent(String(branch))}`;

  if (digit === "1") {
    res.send(`<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say language="kn-IN">
    ಆರ್ ಎನ್ ಎಸ್ ಇನ್ಸ್ಟಿಟ್ಯೂಟ್ ಆಫ್ ಟೆಕ್ನಾಲಜಿ, ಬೆಂಗಳೂರಿನಿಂದ ಶುಭಾಶಯಗಳು.
    ${studentName} ಅವರ ಪೋಷಕರಿಗೆ ಸ್ವಯಂಚಾಲಿತ ಸೂಚನೆ.
    ಅವರ ತರಗತಿ ಹಾಜರಾತಿ ಶೇಕಡಾ 75 ಕ್ಕಿಂತ ಕಡಿಮೆ ಇದೆ ಮತ್ತು ಆಂತರಿಕ ಮೌಲ್ಯಮಾಪನ ಅಂಕಗಳು ಶೇಕಡಾ 60 ಕ್ಕಿಂತ ಕಡಿಮೆ ಇವೆ.
    ದಯವಿಟ್ಟು ತಕ್ಷಣ ಕ್ರಮ ತೆಗೆದುಕೊಳ್ಳಿ. ಧನ್ಯವಾದಗಳು.
  </Say>
</Response>`);
  } else if (digit === "2") {
    res.send(`<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say language="hi-IN" voice="Polly.Aditi">
    आर एन एस इंस्टीट्यूट ऑफ टेक्नोलॉजी, बेंगलुरु की ओर से अभिवादन।
    ${studentName} के माता-पिता को यह स्वचालित सूचना है।
    आपके बच्चे की कक्षा में उपस्थिति 75 प्रतिशत से कम है और आंतरिक मूल्यांकन के अंक 60 प्रतिशत से कम हैं।
    कृपया तत्काल सुधारात्मक कदम उठाएं। यदि यह स्थिति जारी रही तो आपको कॉलेज बुलाया जाएगा।
    धन्यवाद।
  </Say>
</Response>`);
  } else {
    // Repeat or unknown — redirect to main
    res.send(`<?xml version="1.0" encoding="UTF-8"?><Response><Redirect>${mainUrl}</Redirect></Response>`);
  }
});

// Trigger a voice call
router.post("/call", async (req, res) => {
  const userId = (req.session as any)?.userId;
  if (!userId) return res.status(401).json({ error: "Not authenticated" });

  const { studentId, phone } = req.body as { studentId: number; phone: string };
  if (!studentId || !phone) return res.status(400).json({ error: "studentId and phone required" });

  try {
    const client = getTwilioClient();
    const from = process.env.TWILIO_PHONE_NUMBER;
    if (!from) return res.status(500).json({ error: "TWILIO_PHONE_NUMBER not configured" });

    const [student] = await db.select().from(profilesTable).where(eq(profilesTable.id, studentId));
    if (!student) return res.status(404).json({ error: "Student not found" });

    const base = getBaseUrl(req);
    const twimlUrl = `${base}/api/alerts/twiml?studentName=${encodeURIComponent(student.name)}&usn=${encodeURIComponent(student.usn ?? "")}&branch=${encodeURIComponent(student.branch ?? "Computer Science")}`;

    const toNumber = phone.startsWith("+") ? phone : `+91${phone.replace(/\D/g, "")}`;

    const call = await client.calls.create({
      url: twimlUrl,
      to: toNumber,
      from,
    });

    return res.json({ success: true, callSid: call.sid, message: `Call initiated to ${toNumber}` });
  } catch (err: any) {
    req.log.error({ err }, "Failed to initiate call");
    return res.status(500).json({ error: err.message ?? "Failed to initiate call" });
  }
});

// Send WhatsApp alert message
router.post("/whatsapp", async (req, res) => {
  const userId = (req.session as any)?.userId;
