import { useState } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { useQuery } from "@tanstack/react-query";
import { AlertTriangle, Phone, MessageCircle, CheckCircle2, XCircle, Loader2, PhoneCall, ChevronDown, ChevronUp } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";

interface AtRiskStudent {
  id: number;
  name: string;
  usn: string | null;
  section: string | null;
  branch: string | null;
  phone: string | null;
  semester: number | null;
  avgAttendance: number;
  avgCiePct: number;
  avgCie: number;
  lowAttendance: boolean;
  lowMarks: boolean;
  parent: { id: number; name: string; phone: string | null } | null;
}

async function fetchAtRisk(): Promise<AtRiskStudent[]> {
  const r = await fetch("/api/alerts/at-risk", { credentials: "include" });
  if (!r.ok) throw new Error("Failed to fetch at-risk students");
  return r.json();
}

type AlertStatus = "idle" | "loading" | "success" | "error";

function StudentAlertCard({ student }: { student: AtRiskStudent }) {
  const { toast } = useToast();
  const [studentPhone, setStudentPhone] = useState(student.phone ?? "");
  const [parentPhone, setParentPhone] = useState(student.parent?.phone ?? "");
  const [showPhoneEdit, setShowPhoneEdit] = useState(!student.phone);
  const [callStatus, setCallStatus] = useState<{ student: AlertStatus; parent: AlertStatus }>({ student: "idle", parent: "idle" });
  const [waStatus, setWaStatus] = useState<{ student: AlertStatus; parent: AlertStatus }>({ student: "idle", parent: "idle" });

  async function triggerCall(target: "student" | "parent") {
    const phone = target === "student" ? studentPhone : parentPhone;
    if (!phone) {
      toast({ title: "Phone number required", description: `Enter ${target} phone number first`, variant: "destructive" });
      return;
    }
    setCallStatus((s) => ({ ...s, [target]: "loading" }));
    try {
      const r = await fetch("/api/alerts/call", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ studentId: student.id, phone }),
      });
      const data = await r.json();
      if (!r.ok) throw new Error(data.error ?? "Call failed");
      setCallStatus((s) => ({ ...s, [target]: "success" }));
      toast({ title: "📞 Call Initiated!", description: data.message });
    } catch (err: any) {
      setCallStatus((s) => ({ ...s, [target]: "error" }));
      toast({ title: "Call failed", description: err.message, variant: "destructive" });
    }
  }

  async function triggerWhatsApp(target: "student" | "parent") {
    const phone = target === "student" ? studentPhone : parentPhone;
    const parentName = target === "parent" ? (student.parent?.name ?? "Parent") : student.name;
    if (!phone) {
      toast({ title: "Phone number required", description: `Enter ${target} WhatsApp number first`, variant: "destructive" });
      return;
    }
    setWaStatus((s) => ({ ...s, [target]: "loading" }));
    try {
      const r = await fetch("/api/alerts/whatsapp", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          studentId: student.id,
          phone,
          parentName,
          attendance: student.avgAttendance,
          avgMarks: student.avgCiePct,
        }),
      });
      const data = await r.json();
      if (!r.ok) throw new Error(data.error ?? "WhatsApp failed");
      setWaStatus((s) => ({ ...s, [target]: "success" }));
      toast({ title: "💬 WhatsApp Sent!", description: data.message });
    } catch (err: any) {
      setWaStatus((s) => ({ ...s, [target]: "error" }));
      toast({ title: "WhatsApp failed", description: err.message, variant: "destructive" });
    }
  }

  const statusIcon = (s: AlertStatus) => {
    if (s === "loading") return <Loader2 size={14} className="animate-spin" />;
    if (s === "success") return <CheckCircle2 size={14} className="text-emerald-500" />;
    if (s === "error") return <XCircle size={14} className="text-red-500" />;
    return null;
  };

  return (
    <div className="bg-white border border-gray-100 rounded-2xl overflow-hidden shadow-sm">
      {/* Student header */}
      <div className={`px-5 py-4 flex items-start justify-between ${student.lowAttendance && student.lowMarks ? "bg-red-50 border-b border-red-100" : "bg-amber-50 border-b border-amber-100"}`}>
