      {/* Alert actions */}
      <div className="px-5 py-4 grid grid-cols-2 gap-4">
        {/* Student alerts */}
        <div className="space-y-2">
          <div className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-2">Alert Student</div>
          <Button
            size="sm"
            variant="outline"
            className="w-full text-xs border-gray-200 hover:bg-rose-50 hover:border-rose-300 hover:text-rose-700 gap-1.5"
            onClick={() => triggerCall("student")}
            disabled={callStatus.student === "loading"}
          >
            <PhoneCall size={12} />
            {callStatus.student === "loading" ? "Calling…" : "Voice Call"}
            {statusIcon(callStatus.student)}
          </Button>
          <Button
            size="sm"
            variant="outline"
            className="w-full text-xs border-gray-200 hover:bg-emerald-50 hover:border-emerald-300 hover:text-emerald-700 gap-1.5"
            onClick={() => triggerWhatsApp("student")}
            disabled={waStatus.student === "loading"}
          >
            <MessageCircle size={12} />
            {waStatus.student === "loading" ? "Sending…" : "WhatsApp"}
            {statusIcon(waStatus.student)}
          </Button>
        </div>

        {/* Parent alerts */}
        <div className="space-y-2">
          <div className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-2">Alert Parent ({student.parent?.name ?? "No parent linked"})</div>
          <Button
            size="sm"
            variant="outline"
            className="w-full text-xs border-gray-200 hover:bg-rose-50 hover:border-rose-300 hover:text-rose-700 gap-1.5"
            onClick={() => triggerCall("parent")}
            disabled={callStatus.parent === "loading" || !student.parent}
          >
            <PhoneCall size={12} />
            {callStatus.parent === "loading" ? "Calling…" : "Voice Call"}
            {statusIcon(callStatus.parent)}
          </Button>
          <Button
            size="sm"
            variant="outline"
            className="w-full text-xs border-gray-200 hover:bg-emerald-50 hover:border-emerald-300 hover:text-emerald-700 gap-1.5"
            onClick={() => triggerWhatsApp("parent")}
            disabled={waStatus.parent === "loading" || !student.parent}
          >
            <MessageCircle size={12} />
            {waStatus.parent === "loading" ? "Sending…" : "WhatsApp"}
            {statusIcon(waStatus.parent)}
          </Button>
        </div>
      </div>
    </div>
  );
}

