const queryClient = new QueryClient({
  defaultOptions: {
    queries: { refetchOnWindowFocus: false, retry: 1 },
  },
});

function Router() {
  return (
    <Switch>
      <Route path="/" component={Landing} />
      <Route path="/login" component={Login} />
      <Route path="/student" component={StudentDashboard} />
      <Route path="/student/academics" component={StudentAcademics} />
      <Route path="/student/scholarship" component={StudentScholarship} />
      <Route path="/student/grievance" component={StudentGrievance} />
      <Route path="/student/timetable" component={StudentTimetable} />
      <Route path="/student/notes" component={StudentNotes} />
      <Route path="/parent" component={ParentDashboard} />
      <Route path="/parent/chat" component={ParentChat} />
      <Route path="/faculty" component={FacultyDashboard} />
      <Route path="/faculty/students" component={FacultyStudents} />
      <Route path="/faculty/academics" component={FacultyAcademics} />
      <Route path="/faculty/attendance" component={FacultyAttendance} />
      <Route path="/faculty/notes" component={FacultyNotes} />
      <Route path="/faculty/timetable" component={FacultyTimetable} />
      <Route path="/faculty/chat" component={FacultyChat} />
      <Route path="/faculty/alerts" component={FacultyAlertCenter} />
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TenantProvider>
        <TooltipProvider>
          <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
            <AuthProvider>
              <Router />
            </AuthProvider>
          </WouterRouter>
          <Toaster />
        </TooltipProvider>
      </TenantProvider>
    </QueryClientProvider>
  );
}

