export function PortalLayout({ children, theme }: PortalLayoutProps) {
  const { user, setUser } = useAuth();
  const tenant = useTenant();
  const [location] = useLocation();
  const queryClient = useQueryClient();
  const { mutate: logout } = useLogout();

  const navItems = theme === "student" ? studentNav : theme === "parent" ? parentNav : facultyNav;
  const themeClass = theme === "parent" ? "theme-parent" : theme === "faculty" ? "theme-faculty" : "";
  const cfg = sidebarConfig[theme];

  function handleLogout() {
    logout(undefined, {
      onSuccess: () => {
        queryClient.clear();
        setUser(null);
        window.location.href = "/login";
      },
    });
  }

  const initials = user?.name?.split(" ").map((n) => n[0]).join("").slice(0, 2).toUpperCase() ?? "?";

  return (
    <div className={`min-h-screen w-full flex ${themeClass}`}>
