        {/* Portal label */}
        <div className="px-5 py-2.5">
          <div className={`inline-flex items-center gap-1.5 text-[10px] font-semibold uppercase tracking-widest px-2.5 py-1 rounded-full bg-white/10 text-white/60`}>
            <div className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`} />
            {theme} Portal
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 py-2 px-3 space-y-0.5 overflow-y-auto">
          {navItems.map((item) => {
            const rootHref = `/${theme}`;
            const isActive =
              location === item.href ||
              (item.href !== rootHref && location.startsWith(item.href));
            return (
              <Link
                key={item.href}
                href={item.href}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-150 ${
                  isActive
                    ? cfg.accent
                    : `text-white/60 ${cfg.hover}`
                }`}
              >
                <span className={isActive ? "opacity-100" : "opacity-60"}>{item.icon}</span>
                {item.label}
                {item.badge && !isActive && (
                  <span className="ml-auto text-[9px] font-bold bg-amber-400 text-amber-900 px-1.5 py-0.5 rounded-full">
                    {item.badge}
                  </span>
                )}
                {isActive && <ChevronRight size={13} className="ml-auto opacity-40" />}
              </Link>
            );
          })}
        </nav>

        {/* User section */}
        <div className="p-4 border-t border-white/10">
          <div className="flex items-center gap-3 mb-3">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold bg-white/15 text-white ring-1 ring-white/20`}>
