import { Router } from "express";
import twilio from "twilio";
import { db, profilesTable, subjectRecordsTable, parentStudentTable } from "@workspace/db";
import { eq } from "drizzle-orm";

const router = Router();

function getTwilioClient() {
  const sid = process.env.TWILIO_ACCOUNT_SID;
  const token = process.env.TWILIO_AUTH_TOKEN;
  if (!sid || !token) throw new Error("Twilio credentials not configured");
  return twilio(sid, token);
}

function getBaseUrl(req: any): string {
  const domains = process.env.REPLIT_DOMAINS;
  if (domains) return `https://${domains.split(",")[0]}`;
  const devDomain = process.env.REPLIT_DEV_DOMAIN;
  if (devDomain) return `https://${devDomain}`;
  return `${req.protocol}://${req.get("host")}`;
}

// TwiML for the main English message with IVR
router.get("/twiml", (req, res) => {
  res.setHeader("Content-Type", "text/xml");
  const studentName = String(req.query.studentName ?? "the student");
  const usn = String(req.query.usn ?? "");
  const branch = String(req.query.branch ?? "Computer Science");
  const base = getBaseUrl(req);
  const langUrl = `${base}/api/alerts/twiml/language?studentName=${encodeURIComponent(studentName)}&usn=${encodeURIComponent(usn)}&branch=${encodeURIComponent(branch)}`;
  const repeatUrl = `${base}/api/alerts/twiml?studentName=${encodeURIComponent(studentName)}&usn=${encodeURIComponent(usn)}&branch=${encodeURIComponent(branch)}`;

  // Use Polly.Aditi which supports en-IN perfectly
  res.send(`<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Gather numDigits="1" action="${langUrl}" method="POST" timeout="10" finishOnKey="">
    <Say language="en-IN" voice="Polly.Aditi">
      Greetings from R N S Institute of Technology, Bengaluru.
      This is an automated notification for the parents of ${studentName},
      U S N ${usn.split("").join(" ")}, from the ${branch} department.
      Your child's current classroom attendance has dropped below 75 percent
      and internal evaluation marks are below 60 percent, falling to an unsatisfactory level.
      Please take immediate measures to correct this.
      If this trend continues, you will be formally called to the college campus
      for a mandatory evaluation with the branch proctor and the Head of the Department.
      To hear this message in Kannada, press 1.
      For Hindi, press 2.
      To repeat this message, press 0.
      Thank you.
    </Say>
  </Gather>
  <Redirect method="GET">${repeatUrl}</Redirect>
</Response>`);
});

// TwiML language handler — called by Twilio when user presses a digit
router.post("/twiml/language", (req, res) => {
  res.setHeader("Content-Type", "text/xml");
  // Twilio sends Digits in the POST body (form-encoded)
  const digit = String(req.body?.Digits ?? req.query?.Digits ?? "");
  const studentName = String(req.query.studentName ?? "the student");
  const base = getBaseUrl(req);
  const repeatUrl = `${base}/api/alerts/twiml?studentName=${encodeURIComponent(studentName)}&usn=${encodeURIComponent(String(req.query.usn ?? ""))}&branch=${encodeURIComponent(String(req.query.branch ?? "Computer Science"))}`;

  if (digit === "1") {
    // Kannada — use Google Neural voice (supports kn-IN)
    res.send(`<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say language="kn-IN" voice="Google.kn-IN-Standard-A">
