   256→// Get at-risk students (< 75% attendance OR avg CIE < 60%)
   257→router.get("/at-risk", async (req, res) => {
   258→  const userId = (req.session as any)?.userId;
   259→  if (!userId) return res.status(401).json({ error: "Not authenticated" });
   260→
   261→  const [faculty] = await db.select().from(profilesTable).where(eq(profilesTable.id, userId));
   262→  if (!faculty || faculty.role !== "faculty") return res.status(403).json({ error: "Faculty only" });
   263→
   264→  const students = await db.select().from(profilesTable).where(eq(profilesTable.proctorId, userId));
   265→
   266→  const atRisk = [];
   267→  for (const student of students) {
   268→    const subjects = await db.select().from(subjectRecordsTable).where(eq(subjectRecordsTable.studentId, student.id));
   269→    if (subjects.length === 0) continue;
   270→
   271→    const avgAttendance = subjects.reduce((s, r) => s + Number(r.attendance), 0) / subjects.length;
   272→    const avgCie = subjects.reduce((s, r) => s + ((Number(r.cie1 ?? 0) + Number(r.cie2 ?? 0)) / 2), 0) / subjects.length;
   273→    const avgCiePct = (avgCie / 20) * 100;
   274→
   275→    if (avgAttendance < 75 || avgCiePct < 60) {
   276→      const parentLinks = await db.select().from(parentStudentTable).where(eq(parentStudentTable.studentId, student.id));
   277→      let parentInfo = null;
   278→      if (parentLinks.length > 0) {
   279→        const [parent] = await db.select().from(profilesTable).where(eq(profilesTable.id, parentLinks[0]!.parentId));
   280→        if (parent) parentInfo = { id: parent.id, name: parent.name, phone: parent.phone };
   281→      }
   282→
   283→      atRisk.push({
   284→        id: student.id, name: student.name, usn: student.usn, section: student.section,
   285→        branch: student.branch, phone: student.phone, semester: student.semester,
   286→        avgAttendance: Math.round(avgAttendance * 10) / 10,
   287→        avgCiePct: Math.round(avgCiePct * 10) / 10,
   288→        avgCie: Math.round(avgCie * 10) / 10,
   289→        lowAttendance: avgAttendance < 75,
   290→        lowMarks: avgCiePct < 60,
   291→        parent: parentInfo,
   292→      });
   293→    }
   294→  }
   295→
   296→  return res.json(atRisk);
   297→});
