     5→
     6→const router = Router();
     7→
     8→// GET /conversations — list all conversation partners with last message
     9→router.get("/conversations", async (req, res) => {
    10→  const userId = (req.session as any)?.userId;
    11→  if (!userId) return res.status(401).json({ error: "Not authenticated" });
    12→
    13→  const [me] = await db.select().from(profilesTable).where(eq(profilesTable.id, userId));
    14→  if (!me) return res.status(401).json({ error: "Not authenticated" });
    15→
    16→  let partnerIds: number[] = [];
    17→
    18→  if (me.role === "faculty") {
    19→    // Faculty: find all parents of their assigned students
    20→    const myStudents = await db.select().from(profilesTable).where(eq(profilesTable.proctorId, userId));
    21→    for (const student of myStudents) {
    22→      const links = await db.select().from(parentStudentTable).where(eq(parentStudentTable.studentId, student.id));
    23→      for (const link of links) partnerIds.push(link.parentId);
    24→    }
    25→  } else if (me.role === "parent") {
    26→    // Parent: find their children's proctors
    27→    const links = await db.select().from(parentStudentTable).where(eq(parentStudentTable.parentId, userId));
    28→    for (const link of links) {
    29→      const [student] = await db.select().from(profilesTable).where(eq(profilesTable.id, link.studentId));
    30→      if (student?.proctorId) partnerIds.push(student.proctorId);
    31→    }
    32→  }
    33→
    34→  // Deduplicate
    35→  partnerIds = [...new Set(partnerIds)];
    36→
    37→  // For each partner, get last message and their profile
    38→  const conversations = [];
    39→  for (const partnerId of partnerIds) {
    40→    const [partner] = await db.select().from(profilesTable).where(eq(profilesTable.id, partnerId));
    41→    if (!partner) continue;
    42→
    43→    const [lastMsg] = await db
    44→      .select()
    45→      .from(proctorMessagesTable)
    46→      .where(or(
    47→        and(eq(proctorMessagesTable.senderId, userId), eq(proctorMessagesTable.receiverId, partnerId)),
    48→        and(eq(proctorMessagesTable.senderId, partnerId), eq(proctorMessagesTable.receiverId, userId))
    49→      ))
    50→      .orderBy(desc(proctorMessagesTable.createdAt))
    51→      .limit(1);
    52→
    53→    // For faculty: find which student this parent belongs to
    54→    let studentInfo = null;
    55→    if (me.role === "faculty") {
    56→      const link = await db.select().from(parentStudentTable).where(eq(parentStudentTable.parentId, partnerId)).limit(1);
    57→      if (link[0]) {
    58→        const [student] = await db.select().from(profilesTable).where(eq(profilesTable.id, link[0].studentId));
    59→        if (student) studentInfo = { name: student.name, usn: student.usn };
    60→      }
    61→    }
    62→
    63→    conversations.push({
    64→      partnerId,
    65→      partnerName: partner.name,
    66→      partnerRole: partner.role,
    67→      studentInfo,
    68→      lastMessage: lastMsg?.message ?? null,
    69→      lastTime: lastMsg?.createdAt ?? null,
    70→      lastSenderId: lastMsg?.senderId ?? null,
    71→    });
    72→  }
    73→
    74→  // Sort by last message time descending
    75→  conversations.sort((a, b) => {
    76→    if (!a.lastTime && !b.lastTime) return 0;
    77→    if (!a.lastTime) return 1;
    78→    if (!b.lastTime) return -1;
    79→    return new Date(b.lastTime).getTime() - new Date(a.lastTime).getTime();
    80→  });
    81→
    82→  return res.json(conversations);
    83→});
    84→
    85→// GET / — get all messages (optionally filtered by conversation partner)
    86→router.get("/", async (req, res) => {
    87→  const userId = (req.session as any)?.userId;
    88→  if (!userId) return res.status(401).json({ error: "Not authenticated" });
    89→
    90→  const withUserId = req.query.withUserId ? Number(req.query.withUserId) : null;
    91→
    92→  const condition = withUserId
    93→    ? or(
    94→        and(eq(proctorMessagesTable.senderId, userId), eq(proctorMessagesTable.receiverId, withUserId)),
    95→        and(eq(proctorMessagesTable.senderId, withUserId), eq(proctorMessagesTable.receiverId, userId))
    96→      )
    97→    : or(
    98→        eq(proctorMessagesTable.senderId, userId),
    99→        eq(proctorMessagesTable.receiverId, userId)
   100→      );
   101→
   102→  const messages = await db
   103→    .select()
   104→    .from(proctorMessagesTable)
   105→    .where(condition)
   106→    .orderBy(proctorMessagesTable.createdAt);
   107→
   108→  return res.json(messages);
   109→});
