  const [users, setUsers] = useState<AdminUser[]>([]);
  const [tab, setTab] = useState<"overview" | "users" | "demo">("overview");
  const [roleFilter, setRoleFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [reseeding, setReseeding] = useState(false);
  const [editUser, setEditUser] = useState<AdminUser | null>(null);
  const [editForm, setEditForm] = useState({ name: "", email: "", role: "", phone: "" });
  const [newPassword, setNewPassword] = useState("");
  const [showPasswordFor, setShowPasswordFor] = useState<number | null>(null);

  useEffect(() => {
    fetchStats();
    fetchUsers();
  }, []);

  async function fetchStats() {
    try {
      const r = await fetch("/api/admin/stats", { credentials: "include" });
      if (r.ok) setStats(await r.json());
    } catch { }
  }

  async function fetchUsers() {
    try {
      const r = await fetch("/api/admin/users", { credentials: "include" });
      if (r.ok) setUsers(await r.json());
    } catch { }
  }

  async function handleReseed() {
    if (!confirm("This will DELETE all existing data and re-create the demo dataset. Are you sure?")) return;
    setReseeding(true);
    try {
      const r = await fetch("/api/admin/reseed", { method: "POST", credentials: "include" });
      const data = await r.json();
      if (r.ok) {
        toast({ title: "Demo data reset", description: "All demo data has been re-seeded." });
        fetchStats(); fetchUsers();
      } else {
        toast({ title: "Error", description: data.error, variant: "destructive" });
      }
    } catch {
      toast({ title: "Error", description: "Request failed", variant: "destructive" });
    } finally {
      setReseeding(false);
    }
  }

  async function handleDeleteUser(id: number) {
    if (!confirm("Delete this user and all their data? This cannot be undone.")) return;
    const r = await fetch(`/api/admin/users/${id}`, { method: "DELETE", credentials: "include" });
    if (r.ok) {
      toast({ title: "User deleted" });
      fetchUsers(); fetchStats();
    } else {
      const data = await r.json();
      toast({ title: "Error", description: data.error, variant: "destructive" });
    }
  }

  async function handleSaveEdit() {
    if (!editUser) return;
    const r = await fetch(`/api/admin/users/${editUser.id}`, {
      method: "PATCH",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(editForm),
    });
    if (r.ok) {
      toast({ title: "User updated" });
      setEditUser(null);
      fetchUsers();
    } else {
      const data = await r.json();
      toast({ title: "Error", description: data.error, variant: "destructive" });
