    const r = await fetch(`/api/admin/reset-password/${id}`, {
      method: "POST",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ password: newPassword }),
    });
    if (r.ok) {
      toast({ title: "Password updated" });
      setShowPasswordFor(null);
